"use strict";(self.webpackChunkageyev_github_io=self.webpackChunkageyev_github_io||[]).push([[2935],{2027:(e,t,i)=>{i.r(t),i.d(t,{assets:()=>o,contentTitle:()=>h,default:()=>c,frontMatter:()=>r,metadata:()=>n,toc:()=>l});const n=JSON.parse('{"id":"theology/tahrif","title":"Tahrif","description":"Religious-Normative Foundation for the Expansion of the Abraham Accords","source":"@site/docs/theology/tahrif.md","sourceDirName":"theology","slug":"/theology/tahrif","permalink":"/theology/tahrif","draft":false,"unlisted":false,"tags":[{"inline":false,"label":"theology","permalink":"/tags/theology","description":"Theology"},{"inline":false,"label":"Islam","permalink":"/tags/islam","description":"Islam"}],"version":"current","lastUpdatedBy":"ageyev","lastUpdatedAt":1781201960000,"frontMatter":{"title":"Tahrif","id":"tahrif","hide_title":true,"draft":false,"tags":["theology","Islam"],"lang":"en","description":"Religious-Normative Foundation for the Expansion of the Abraham Accords","image":"/img/Illustrations/docs/theology/old_scroll_and_light_Gr_001.jpg","keywords":["Tahrif","Quran"]},"sidebar":"docs","previous":{"title":"Al-Aqsa","permalink":"/theology/al-aqsa"},"next":{"title":"ECHR","permalink":"/ECHR/"}}');var a=i(4848),s=i(8453);const r={title:"Tahrif",id:"tahrif",hide_title:!0,draft:!1,tags:["theology","Islam"],lang:"en",description:"Religious-Normative Foundation for the Expansion of the Abraham Accords",image:"/img/Illustrations/docs/theology/old_scroll_and_light_Gr_001.jpg",keywords:["Tahrif","Quran"]},h="Tahrif (\u062a\u062d\u0631\u064a\u0641)",o={},l=[{value:"Introduction",id:"introduction",level:2},{value:"Is renewal of the Islamic tradition possible?",id:"is-renewal-of-the-islamic-tradition-possible",level:3},{value:"On the possibility and the obligation of accepting a well-grounded position in theology",id:"on-the-possibility-and-the-obligation-of-accepting-a-well-grounded-position-in-theology",level:3},{value:"Is it legitimate for a person not raised within, or not standing inside, the tradition to understand and interpret the Quran?",id:"is-it-legitimate-for-a-person-not-raised-within-or-not-standing-inside-the-tradition-to-understand-and-interpret-the-quran",level:3},{value:"Tahrif and its understanding",id:"tahrif-and-its-understanding",level:2},{value:"Arguments against the concept of corruption of the Torah&#39;s text",id:"arguments-against-the-concept-of-corruption-of-the-torahs-text",level:2},{value:"The principal argument: Isa (Jesus)",id:"the-principal-argument-isa-jesus",level:3},{value:"The verses about Isa",id:"the-verses-about-isa",level:4},{value:"The text of the Tawrat that Isa used",id:"the-text-of-the-tawrat-that-isa-used",level:4},{value:"Additional arguments",id:"additional-arguments",level:3},{value:"Verses with a grammatically built-in presumption that the authentic Tawrat was in the possession of contemporaries",id:"verses-with-a-grammatically-built-in-presumption-that-the-authentic-tawrat-was-in-the-possession-of-contemporaries",level:4},{value:"5:43:",id:"543",level:5},{value:"2:91:",id:"291",level:5},{value:"2:101:",id:"2101",level:5},{value:"4:47:",id:"447",level:5},{value:"Verses with demands that the Jews read or observe the Tawrat",id:"verses-with-demands-that-the-jews-read-or-observe-the-tawrat",level:4},{value:"3:93:",id:"393",level:5},{value:"5:68:",id:"568",level:5},{value:"The Hadith on Stoning.",id:"the-hadith-on-stoning",level:4},{value:"On the text of the Quran itself",id:"on-the-text-of-the-quran-itself",level:2},{value:"On using the Torah to clarify the meanings of the Quran",id:"on-using-the-torah-to-clarify-the-meanings-of-the-quran",level:2},{value:"Conclusions",id:"conclusions",level:2},{value:"References",id:"references",level:2}];function d(e){const t={a:"a",admonition:"admonition",blockquote:"blockquote",em:"em",h1:"h1",h2:"h2",h3:"h3",h4:"h4",h5:"h5",header:"header",hr:"hr",li:"li",p:"p",strong:"strong",ul:"ul",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.admonition,{title:"Reading Arabic",type:"tip",children:(0,a.jsxs)(t.p,{children:["This page contains Arabic text. To read Arabic more comfortably on multilingual pages, you may find my Chrome extension useful: ",(0,a.jsx)(t.a,{href:"/tools/enlarge_arabic",children:"[Enlarge Arabic]"}),", which can be ",(0,a.jsx)(t.a,{href:"https://chromewebstore.google.com/detail/enlarge-arabic/cohiboahimednknkffilddeindcgpiop",children:"installed"})," from the Chrome Web Store."]})}),"\n",(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"tahrif-\u062a\u062d\u0631\u064a\u0641",children:"Tahrif (\u062a\u062d\u0631\u064a\u0641)"})}),"\n",(0,a.jsx)(t.h2,{id:"introduction",children:"Introduction"}),"\n",(0,a.jsx)(t.p,{children:"A necessary clarification of what this text is about and why: it is part of a project to build the religious-normative component of an international-legal framework for a peaceful settlement of the war in the Middle East."}),"\n",(0,a.jsx)(t.p,{children:"The Abraham Accords remain suspended because they are based primarily on economic considerations and fear of Iran. They significantly lack a theological basis that would justify normalizing relations with Israel in the eyes of Arab and Muslim societies."}),"\n",(0,a.jsx)(t.p,{children:"But before we turn to the substantive questions, we must answer the predictable objections to the very legitimacy of the inquiry and of the conclusions I draw."}),"\n",(0,a.jsxs)(t.p,{children:['These are objections I have already encountered, in particular in discussing the text on what exactly is meant by the "Farthest Mosque/Temple" in the Quran (see the text ',(0,a.jsx)(t.a,{href:"https://international-law.info/theology/al-aqsa/",children:'"Al-Aqsa"'}),' on my site), and they are two: 1) Islam cannot abandon traditions that have taken shape over the centuries, and 2) "you cannot interpret the Quran from outside the tradition," in a softer variant: "you are an intelligent person, but we must believe our authoritative theologians."']}),"\n",(0,a.jsx)(t.h3,{id:"is-renewal-of-the-islamic-tradition-possible",children:"Is renewal of the Islamic tradition possible?"}),"\n",(0,a.jsx)(t.p,{children:"One of the foundations of Islam \u2014 to a large extent its distinctive feature in comparison with other religious movements \u2014 is the postulate that a tradition inevitably accumulates a layer of distortions over time, and that a periodic return to the sources is not merely possible but a prescribed action."}),"\n",(0,a.jsxs)(t.p,{children:["Indeed, Islam has a special term for this \u2014\n",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Islamic_revival",children:"tajdid"}),'\n(\u062a\u062c\u062f\u064a\u062f)\n, meaning "renewal," derived from the root \u062c-\u062f-\u062f (j-d-d). From the same root comes the term ',(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Mujaddid",children:"mujaddid"}),'\n(\u0645\u062c\u062f\u062f)\n\u2014 "renewer, reformer."']}),"\n",(0,a.jsxs)(t.p,{children:["Innovations \u2014 ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Bid%27ah",children:"bid'ah"}),"\n(\u0628\u062f\u0639\u0629)\n\u2014 are condemned in Islam, whereas tajdid \u2014 renewal through a return to the original meanings \u2014 is held to be good and necessary."]}),"\n",(0,a.jsxs)(t.p,{children:["A key basis of this concept is the words of Muhammad transmitted in hadith ",(0,a.jsx)(t.a,{href:"https://sunnah.com/abudawud:4291",children:"4291"}),' of Sunan Abu Dawud, the Book of "Al-Malahim" (Battles/Portents):']}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0625\u0650\u0646\u064e\u0651 \u0627\u0644\u0644\u064e\u0651\u0647\u064e \u064a\u064e\u0628\u0652\u0639\u064e\u062b\u064f \u0644\u0650\u0647\u064e\u0630\u0650\u0647\u0650 \u0627\u0644\u0623\u064f\u0645\u064e\u0651\u0629\u0650 \u0639\u064e\u0644\u064e\u0649 \u0631\u064e\u0623\u0652\u0633\u0650 \u0643\u064f\u0644\u0650\u0651 \u0645\u0650\u0627\u0626\u064e\u0629\u0650 \u0633\u064e\u0646\u064e\u0629\u064d \u0645\u064e\u0646\u0652 \u064a\u064f\u062c\u064e\u062f\u0650\u0651\u062f\u064f \u0644\u064e\u0647\u064e\u0627 \u062f\u0650\u064a\u0646\u064e\u0647\u064e\u0627"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"For at the head of every century Allah will send to this Ummah someone who will renew its religion for it."}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:['In this case the translation is mine. Islamic theologians debated the meaning of the expression \u0639\u064e\u0644\u064e\u0649 \u0631\u064e\u0623\u0652\u0633\u0650 \u2014 whether it means "at the beginning" or "at the end" (of the century). The prevailing view today is that it refers to the end of the century (contrary to the word\'s usual meaning), on the grounds that ',(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Umar_ibn_Abd_al-Aziz",children:"Umar ibn Abd al-Aziz"}),", regarded as the first mujaddid, died in the year 101 of the Hijra, while ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Al-Shafi%27i",children:"al-Shafi'i"})," died in the year 204."]}),"\n",(0,a.jsx)(t.p,{children:'I, however, hold \u2014 relying, among other things, on the meaning of the root in Hebrew and its reflex in Arabic (\u0631\u064e\u0623\u0652\u0633\u0650 \u2014 ra\u02bcs, the same as Hebrew \u05e8\u05d0\u05e9 \u2014 rosh, i.e. etymologically "head") \u2014 that this denotes not so much the "beginning" of a time period as the setting of its direction or meaning. That is, the correct translation is neither the literal "at the beginning" nor "at the end" (as the historical analysis would have it), but precisely "at the head."'}),"\n",(0,a.jsx)(t.p,{children:"One way or another, the Islamic tradition recognizes not only the possibility but the necessity of periodically renewing the religion through a return to its sources."}),"\n",(0,a.jsx)(t.h3,{id:"on-the-possibility-and-the-obligation-of-accepting-a-well-grounded-position-in-theology",children:"On the possibility and the obligation of accepting a well-grounded position in theology"}),"\n",(0,a.jsx)(t.p,{children:"Here, too, a necessary observation about theological disputes must be made, one that may not be obvious to the reader."}),"\n",(0,a.jsx)(t.p,{children:"Unlike purely secular scholarly disputes, in a discussion where the parties presuppose, as an accepted basis, the existence of the Most High, the knowability of His will, and the authority of the text that describes it (in this case, at least, the Quran), the attitude toward well-argued conclusions is (contrary to the widespread opposite belief) far stricter."}),"\n",(0,a.jsx)(t.p,{children:"On the question of the genetic mutations of the fruit fly, a secular scholar is relatively free to hold a position refuted by other scholars' arguments; this may damage his reputation, but it is, broadly speaking, not so dangerous. In a theological dispute, refusing to follow the truth has not only an epistemic but also a religious-moral dimension."}),"\n",(0,a.jsxs)(t.p,{children:["If a person acknowledges revelation and the will of the Most High, he cannot choose a position merely because it is politically advantageous or convenient. He must either show by his arguments that his opponent's position is wrong, or at least debatable, or else accept it \u2014 otherwise he commits a sin. For example, ",(0,a.jsx)(t.em,{children:"if"}),' it is proven (textually and historically) that the tahrif spoken of in the Quran is not a change in the text of the Tawrat but a misinterpretation of it, then a person who calls himself a Muslim and nonetheless keeps insisting on the opposite simply "because that is how it is done" commits kufr (\u0643\u0641\u0631) \u2014 the concealment/denial of the truth (the root \u0643-\u0641-\u0631, the common-Semitic ',(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/K-P-R",children:"K-F/P-R"}),', originally meant "to conceal" among the Arabs, and the word "',(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Kafir#Etymology",children:"kafir"}),'" means "the one who conceals").']}),"\n",(0,a.jsxs)(t.p,{children:['To avoid misunderstanding, let me emphasize: kufr is not "to misunderstand"; kufr is to hear well-grounded arguments in favor of a particular position and, ',(0,a.jsx)(t.em,{children:"while understanding the soundness of the arguments"}),', to reject them because: "they were put forward by a Jew," "we are used to understanding it differently," "I have my own position and I do not want to change it," and the like.']}),"\n",(0,a.jsx)(t.p,{children:"And it is important to place this at the foundation of interreligious dialogue, including between Judaism and Islam. Whoever is unwilling to conduct it honestly thereby already, plainly and decisively, loses it."}),"\n",(0,a.jsx)(t.p,{children:"What I am asserting here, I assert honestly, with the aim of establishing the truth and the will of the Most High. I am ready to accept objections and counterarguments on the merits. And this gives me the right to demand: either present arguments showing that I am wrong or that my position is debatable, or else explain what motives guide you in rejecting proven assertions. And if those motives lie outside an honest search for the meaning of the sacred texts and the will of the Most High, let us acknowledge this openly \u2014 but then you are also compelled to admit that your war is meaningless and doomed to defeat."}),"\n",(0,a.jsx)(t.p,{children:"It should be noted that a similar situation obtains in legal disputes. In law, as in theology, a position is not a matter of private taste. It claims normative force. Where a position can affect people's lives and freedom, the demands on the participants' epistemological honesty are far higher. A court, for example, has no right to reject a well-argued position simply by appealing to the fact that \"well, we have a different opinion,\" if there are no counterarguments \u2014 here there is a duty to agree."}),"\n",(0,a.jsx)(t.p,{children:"What we are examining here is not a dispute about ancient history; it is a dispute about law, in which the body of international-legal norms actually in force must, among other things, formally incorporate religious law as well."}),"\n",(0,a.jsxs)(t.p,{children:["International law (in particular, Art. 2(3) of the ",(0,a.jsx)(t.a,{href:"https://www.un.org/en/about-us/un-charter/full-text",children:"UN Charter"}),") requires states to seek peaceful means of resolving disputes. Religious doctrines that influence an armed conflict must be the subject of open, documented, well-argued, and publicly verifiable dialogue. And this is the path to peace, and to truth."]}),"\n",(0,a.jsx)(t.p,{children:"And this is precisely what the official position of the parties \u2014 including Israel and the Muslim states \u2014 should become in negotiations."}),"\n",(0,a.jsx)(t.p,{children:"In particular, Israel can and should declare: the attempt to settle a theological-political dispute by war has not given your arguments victory; therefore, if we do not wish to return to war endlessly, the dispute must be transferred into the space of text, reason, and honest theological analysis."}),"\n",(0,a.jsx)(t.h3,{id:"is-it-legitimate-for-a-person-not-raised-within-or-not-standing-inside-the-tradition-to-understand-and-interpret-the-quran",children:"Is it legitimate for a person not raised within, or not standing inside, the tradition to understand and interpret the Quran?"}),"\n",(0,a.jsx)(t.p,{children:"(1)"}),"\n",(0,a.jsx)(t.p,{children:"Here, first of all, one must note that Islam itself, as an ideological system, is constitutively founded on the interpretation of texts lying outside the Islamic tradition proper \u2014 namely the Torah (Tawrat / \u062a\u0648\u0631\u0627\u0629) and the Gospels (Injil / \u0625\u0646\u062c\u064a\u0644) \u2014 by people who stand outside those traditions (i.e. who are neither Jews nor Christians) and who, moreover, are not prophets (apart from Muhammad himself)."}),"\n",(0,a.jsx)(t.p,{children:'That is, even the appeal to the prophetic gift works only for Muhammad himself. And under the approach "one may not interpret from outside the tradition," most Muslim scholars could be accused of judging, without being prophets, traditions whose languages they do not understand, including in the literal sense (Hebrew and Aramaic for the Israelites, and Greek and Latin for Christianity).'}),"\n",(0,a.jsx)(t.p,{children:'That is, the approach "one cannot judge except from inside the tradition" does not work within Islam itself.'}),"\n",(0,a.jsx)(t.p,{children:"(2)"}),"\n",(0,a.jsxs)(t.p,{children:["The ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Companions_of_the_Prophet",children:"Sahaba"})," (\u0627\u0644\u0635\u062d\u0627\u0628\u0629) \u2014 the founders of Islam, the companions of the Prophet Muhammad \u2014 were not people originally raised or educated within the Islamic tradition. And the great caliph Umar (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Umar",children:"Umar ibn al-Khattab"}),") was originally an opponent of Islam and intended to kill Muhammad for having defamed the religion of the ancestors and condemned the worship of idols."]}),"\n",(0,a.jsxs)(t.p,{children:["Many of the companions came to understanding before meeting the Prophet (Umar read the Quran in his sister's house; the first Medinan Muslims sent people to Muhammad in Mecca to learn the Quran). The claim that a modern reader cannot understand the Quran without already being a Muslim beforehand would contradict the Islamic doctrine of the Quran as a clear exposition \u2014 bayan \u0628\u064e\u064a\u064e\u0627\u0646, see ",(0,a.jsx)(t.a,{href:"https://quran.com/3/138",children:"3:138"}),' (the same Semitic root: \u05d1-\u05d9-\u05e0 (b-y-n) \u2014 "to understand, to distinguish," from which also \u05d1\u05b4\u05bc\u05d9\u05e0\u05b8\u05d4 (binah \u2014 "understanding")).']}),"\n",(0,a.jsx)(t.p,{children:'At the same time it must be noted that "clarity" does not mean that the Quran is comprehensible apart from the preceding Scripture, which it presupposes and confirms \u2014 it rests on the referential background, contemporary to it, of the preceding sacred texts, just as a clear judicial decision rests on a law known to the reader without thereby becoming "incomplete."'}),"\n",(0,a.jsx)(t.p,{children:"(3)"}),"\n",(0,a.jsx)(t.p,{children:'The rule "the text may be interpreted only by members of a particular school" implicitly entails declaring either that text or that school to be false.'}),"\n",(0,a.jsx)(t.p,{children:"For to assert that only those who agree with the text have the right to interpret it amounts to admitting that the text is incapable of withstanding the criticism of those who disagree with it. Or, if one holds that only members of a particular school may interpret the text, this will amount to admitting that the school's approach cannot withstand external criticism."}),"\n",(0,a.jsx)(t.p,{children:"Any system of views that rejects the possibility of being analyzed from outside thereby asserts, epistemologically, its own untenability."}),"\n",(0,a.jsx)(t.p,{children:"When, within a community, the very fact of talking with an opponent is classified as betrayal, this is diagnostically significant. It is a sign that the community is not confident in its position's ability to withstand an open clash with arguments from outside. A system confident of its victory in an open clash of ideas has no need to declare the clash itself a betrayal."}),"\n",(0,a.jsx)(t.p,{children:"(4)"}),"\n",(0,a.jsx)(t.p,{children:"Although Islam and appeals to the Quran currently serve as the foundation of wars against Israel, practice shows that the Muslims who invoke the Quran on so supremely serious a theme as the religious foundation of war are astonishingly ignorant of the text of the Quran."}),"\n",(0,a.jsxs)(t.p,{children:['A vivid example here is the slogan that Hamas chose for its war with Israel, which it named the "Al-Aqsa Flood" (',(0,a.jsx)(t.a,{href:"https://www.palestinechronicle.com/wp-content/uploads/2024/01/PDF.pdf",children:"Al-Aqsa Flood"}),"). This slogan was a quotation from the Quran, ",(0,a.jsx)(t.a,{href:"https://quran.com/5?startingVerse=23",children:"5:23"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0627\u062f\u0652\u062e\u064f\u0644\u064f\u0648\u0627 \u0639\u064e\u0644\u064e\u064a\u0652\u0647\u0650\u0645\u064f \u0627\u0644\u0652\u0628\u064e\u0627\u0628\u064e \u0641\u064e\u0625\u0650\u0630\u064e\u0627 \u062f\u064e\u062e\u064e\u0644\u0652\u062a\u064f\u0645\u064f\u0648\u0647\u064f \u0641\u064e\u0625\u0650\u0646\u064e\u0651\u0643\u064f\u0645\u0652 \u063a\u064e\u0627\u0644\u0650\u0628\u064f\u0648\u0646\u064e"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"Surprise them through the gate. If you do, you will certainly prevail.\n(English translation: Dr. Mustafa Khattab)"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"Evidently the reason for using this quotation as a slogan was the victory it promises."}),"\n",(0,a.jsxs)(t.p,{children:['There is, however, the question of who the "you" in this phrase are. In the Quran this phrase is addressed... to the Israelites, and it promises victory in the war for the Holy Land precisely to the ',(0,a.jsx)(t.em,{children:"Israelites"}),"."]}),"\n",(0,a.jsxs)(t.p,{children:["What is curious is that, although during the period of active hostilities this slogan was widely used by Hamas (see ",(0,a.jsx)(t.a,{target:"_blank","data-noBrokenLinkCheck":!0,href:i(6178).A+"",children:"the standard splash screen of their videos"}),') and was quoted as "inspiring," apparently ',(0,a.jsx)(t.em,{children:"no one"})," in the Muslim (at least, as far as could be established, the Arabic- and Persian-speaking) public sphere paid attention to the meaning of this phrase in the Quran."]}),"\n",(0,a.jsx)(t.p,{children:"It is not surprising that the ignorant Hamas members were defeated in this war against Israel. Which is a graphic example of how ruinous a careless handling of the Quranic text can be."}),"\n",(0,a.jsx)(t.p,{children:"(5)"}),"\n",(0,a.jsx)(t.p,{children:"From my own experience, it seems to me that an understanding of both the content and the language of the Quran cannot be sufficiently complete without a basic knowledge of the Jewish religious tradition and of Hebrew."}),"\n",(0,a.jsx)(t.p,{children:"(6)"}),"\n",(0,a.jsxs)(t.p,{children:["And finally, the most interesting point. The Quran itself appeals to the position of knowledgeable people from the Judeo-Christian tradition as a criterion even for Muhammad himself. In verse ",(0,a.jsx)(t.a,{href:"https://quran.com/10?startingVerse=94",children:"10:94"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0641\u064e\u0625\u0650\u0646 \u0643\u064f\u0646\u062a\u064e \u0641\u0650\u0649 \u0634\u064e\u0643\u064d\u0651\u06e2 \u0645\u0650\u0651\u0645\u064e\u0651\u0622 \u0623\u064e\u0646\u0632\u064e\u0644\u0652\u0646\u064e\u0622 \u0625\u0650\u0644\u064e\u064a\u0652\u0643\u064e \u0641\u064e\u0633\u0652\u0640\u064e\u0654\u0644\u0650 \u0671\u0644\u064e\u0651\u0630\u0650\u064a\u0646\u064e \u064a\u064e\u0642\u0652\u0631\u064e\u0621\u064f\u0648\u0646\u064e \u0671\u0644\u0652\u0643\u0650\u062a\u064e\u0640\u0670\u0628\u064e \u0645\u0650\u0646"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"If you \u02f9O Prophet\u02fa are in doubt about \u02f9these stories\u02fa that We have revealed to you, then ask those who read the Scripture before you.\n(English translation: Dr. Mustafa Khattab)"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"This verse is significant not only for methodology but for the substance of our inquiry into tahrif \u2014 that is, whether the Quran asserts that the text of the Torah had already been changed or lost by the time of the Quran's revelation, or whether the point is only the existence of distorted interpretations of that text."}),"\n",(0,a.jsx)(t.p,{children:'The verb \u064a\u064e\u0642\u0652\u0631\u064e\u0621\u064f\u0648\u0646\u064e (yaqra\u02be\u016bna) \u2014 "they read." The readers of the prior Scripture at that time are precisely the Jews and Christians with their texts. If those texts that they were reading are a forgery, then the advice to the Prophet, in case of doubt, to ask the readers of a forgery is absurd.'}),"\n",(0,a.jsx)(t.p,{children:"And so we move on to examining the theme of tahrif on the merits."}),"\n",(0,a.jsx)(t.h2,{id:"tahrif-and-its-understanding",children:"Tahrif and its understanding"}),"\n",(0,a.jsx)(t.p,{children:'The word \u062a\u064e\u062d\u0652\u0631\u0650\u064a\u0641 (tahrif) itself is not used in the Quran, but the Quran does contain cognate verbs of the root \u062d-\u0631-\u0641 (\u1e25-r-f) \u2014 "to bend, to distort, to shift from its place."'}),"\n",(0,a.jsx)(t.p,{children:'According to the Quranic Arabic Corpus, the root \u062d-\u0631-\u0641 occurs in the Quran 6 times, but specifically as the verb "to distort" \u2014 4 times:'}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.a,{href:"https://quran.com/2?startingVerse=75",children:"2:75"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0623\u064e\u0641\u064e\u062a\u064e\u0637\u0652\u0645\u064e\u0639\u064f\u0648\u0646\u064e \u0623\u064e\u0646 \u064a\u064f\u0624\u0652\u0645\u0650\u0646\u064f\u0648\u0627 \u0644\u064e\u0643\u064f\u0645\u0652 \u0648\u064e\u0642\u064e\u062f\u0652 \u0643\u064e\u0627\u0646\u064e \u0641\u064e\u0631\u0650\u064a\u0642\u064c \u0645\u0650\u0651\u0646\u0652\u0647\u064f\u0645\u0652 \u064a\u064e\u0633\u0652\u0645\u064e\u0639\u064f\u0648\u0646\u064e \u0643\u064e\u0644\u064e\u0627\u0645\u064e \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u062b\u064f\u0645\u064e\u0651 \u064a\u064f\u062d\u064e\u0631\u0650\u0651\u0641\u064f\u0648\u0646\u064e\u0647\u064f \u0645\u0650\u0646 \u0628\u064e\u0639\u0652\u062f\u0650 \u0645\u064e\u0627 \u0639\u064e\u0642\u064e\u0644\u064f\u0648\u0647\u064f \u0648\u064e\u0647\u064f\u0645\u0652 \u064a\u064e\u0639\u0652\u0644\u064e\u0645\u064f\u0648\u0646\u064e"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"Do you \u02f9believers still\u02fa expect them to be true to you, though a group of them would hear the word of Allah then knowingly corrupt it after understanding it?\n(English translation: Dr. Mustafa Khattab)"}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.a,{href:"https://quran.com/4?startingVerse=46",children:"4:46"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0645\u0650\u0651\u0646\u064e \u0627\u0644\u064e\u0651\u0630\u0650\u064a\u0646\u064e \u0647\u064e\u0627\u062f\u064f\u0648\u0627 \u064a\u064f\u062d\u064e\u0631\u0650\u0651\u0641\u064f\u0648\u0646\u064e \u0627\u0644\u0652\u0643\u064e\u0644\u0650\u0645\u064e \u0639\u064e\u0646 \u0645\u064e\u0651\u0648\u064e\u0627\u0636\u0650\u0639\u0650\u0647\u0650 \u0648\u064e\u064a\u064e\u0642\u064f\u0648\u0644\u064f\u0648\u0646\u064e \u0633\u064e\u0645\u0650\u0639\u0652\u0646\u064e\u0627 \u0648\u064e\u0639\u064e\u0635\u064e\u064a\u0652\u0646\u064e\u0627 \u0648\u064e\u0627\u0633\u0652\u0645\u064e\u0639\u0652 \u063a\u064e\u064a\u0652\u0631\u064e \u0645\u064f\u0633\u0652\u0645\u064e\u0639\u064d \u0648\u064e\u0631\u064e\u0627\u0639\u0650\u0646\u064e\u0627 \u0644\u064e\u064a\u064b\u0651\u0627 \u0628\u0650\u0623\u064e\u0644\u0652\u0633\u0650\u0646\u064e\u062a\u0650\u0647\u0650\u0645\u0652 \u0648\u064e\u0637\u064e\u0639\u0652\u0646\u064b\u0627 \u0641\u0650\u064a \u0627\u0644\u062f\u0650\u0651\u064a\u0646\u0650 \u0648\u064e\u0644\u064e\u0648\u0652 \u0623\u064e\u0646\u064e\u0651\u0647\u064f\u0645\u0652 \u0642\u064e\u0627\u0644\u064f\u0648\u0627 \u0633\u064e\u0645\u0650\u0639\u0652\u0646\u064e\u0627 \u0648\u064e\u0623\u064e\u0637\u064e\u0639\u0652\u0646\u064e\u0627 \u0648\u064e\u0627\u0633\u0652\u0645\u064e\u0639\u0652 \u0648\u064e\u0627\u0646\u0638\u064f\u0631\u0652\u0646\u064e\u0627 \u0644\u064e\u0643\u064e\u0627\u0646\u064e \u062e\u064e\u064a\u0652\u0631\u064b\u0627 \u0644\u064e\u0651\u0647\u064f\u0645\u0652 \u0648\u064e\u0623\u064e\u0642\u0652\u0648\u064e\u0645\u064e \u0648\u064e\u0644\u064e\u0643\u0650\u0646 \u0644\u064e\u0651\u0639\u064e\u0646\u064e\u0647\u064f\u0645\u064f \u0627\u0644\u0644\u064e\u0651\u0647\u064f \u0628\u0650\u0643\u064f\u0641\u0652\u0631\u0650\u0647\u0650\u0645\u0652 \u0641\u064e\u0644\u064e\u0627 \u064a\u064f\u0624\u0652\u0645\u0650\u0646\u064f\u0648\u0646\u064e \u0625\u0650\u0644\u064e\u0651\u0627 \u0642\u064e\u0644\u0650\u064a\u0644\u064b\u0627"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:'Some Jews take words out of context and say, "We listen and we disobey," "Hear! May you never hear," and "R\xe2\'ina!" [Herd us!]\u2014playing with words and discrediting the faith. Had they said \u02f9courteously\u02fa, "We hear and obey," "Listen to us," and "Un\u1e93urna," [Tend to us!] it would have been better for them and more proper. Allah has condemned them for their disbelief, so they do not believe except for a few.\n(English translation: Dr. Mustafa Khattab)'}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.a,{href:"https://quran.com/5?startingVerse=13",children:"5:13"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0641\u064e\u0628\u0650\u0645\u064e\u0627 \u0646\u064e\u0642\u0652\u0636\u0650\u0647\u0650\u0645 \u0645\u0650\u0651\u064a\u062b\u064e\u0627\u0642\u064e\u0647\u064f\u0645\u0652 \u0644\u064e\u0639\u064e\u0646\u064e\u0651\u0627\u0647\u064f\u0645\u0652 \u0648\u064e\u062c\u064e\u0639\u064e\u0644\u0652\u0646\u064e\u0627 \u0642\u064f\u0644\u064f\u0648\u0628\u064e\u0647\u064f\u0645\u0652 \u0642\u064e\u0627\u0633\u0650\u064a\u064e\u0629\u064b \u064a\u064f\u062d\u064e\u0631\u0650\u0651\u0641\u064f\u0648\u0646\u064e \u0627\u0644\u0652\u0643\u064e\u0644\u0650\u0645\u064e \u0639\u064e\u0646 \u0645\u064e\u0651\u0648\u064e\u0627\u0636\u0650\u0639\u0650\u0647\u0650 \u0648\u064e\u0646\u064e\u0633\u064f\u0648\u0627 \u062d\u064e\u0638\u064b\u0651\u0627 \u0645\u0650\u0651\u0645\u064e\u0651\u0627 \u0630\u064f\u0643\u0650\u0651\u0631\u064f\u0648\u0627 \u0628\u0650\u0647\u0650 \u0648\u064e\u0644\u064e\u0627 \u062a\u064e\u0632\u064e\u0627\u0644\u064f \u062a\u064e\u0637\u064e\u0651\u0644\u0650\u0639\u064f \u0639\u064e\u0644\u064e\u0649 \u062e\u064e\u0627\u0626\u0650\u0646\u064e\u0629\u064d \u0645\u0650\u0651\u0646\u0652\u0647\u064f\u0645\u0652 \u0625\u0650\u0644\u064e\u0651\u0627 \u0642\u064e\u0644\u0650\u064a\u0644\u064b\u0627 \u0645\u0650\u0651\u0646\u0652\u0647\u064f\u0645\u0652 \u0641\u064e\u0627\u0639\u0652\u0641\u064f \u0639\u064e\u0646\u0652\u0647\u064f\u0645\u0652 \u0648\u064e\u0627\u0635\u0652\u0641\u064e\u062d\u0652 \u0625\u0650\u0646\u064e\u0651 \u0627\u0644\u0644\u064e\u0651\u0647\u064e \u064a\u064f\u062d\u0650\u0628\u064f\u0651 \u0627\u0644\u0652\u0645\u064f\u062d\u0652\u0633\u0650\u0646\u0650\u064a\u0646\u064e"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"But for breaking their covenant We condemned them and hardened their hearts. They distorted the words of the Scripture and neglected a portion of what they had been commanded to uphold. You \u02f9O Prophet\u02fa will always find deceit on their part, except for a few. But pardon them and bear with them. Indeed, Allah loves the good-doers.\n(English translation: Dr. Mustafa Khattab)"}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.a,{href:"https://quran.com/5?startingVerse=41",children:"5:41"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u064a\u064e\u0627 \u0623\u064e\u064a\u064f\u0651\u0647\u064e\u0627 \u0627\u0644\u0631\u064e\u0651\u0633\u064f\u0648\u0644\u064f \u0644\u064e\u0627 \u064a\u064e\u062d\u0652\u0632\u064f\u0646\u0643\u064e \u0627\u0644\u064e\u0651\u0630\u0650\u064a\u0646\u064e \u064a\u064f\u0633\u064e\u0627\u0631\u0650\u0639\u064f\u0648\u0646\u064e \u0641\u0650\u064a \u0627\u0644\u0652\u0643\u064f\u0641\u0652\u0631\u0650 \u0645\u0650\u0646\u064e \u0627\u0644\u064e\u0651\u0630\u0650\u064a\u0646\u064e \u0642\u064e\u0627\u0644\u064f\u0648\u0627 \u0622\u0645\u064e\u0646\u064e\u0651\u0627 \u0628\u0650\u0623\u064e\u0641\u0652\u0648\u064e\u0627\u0647\u0650\u0647\u0650\u0645\u0652 \u0648\u064e\u0644\u064e\u0645\u0652 \u062a\u064f\u0624\u0652\u0645\u0650\u0646 \u0642\u064f\u0644\u064f\u0648\u0628\u064f\u0647\u064f\u0645\u0652 \u0648\u064e\u0645\u0650\u0646\u064e \u0627\u0644\u064e\u0651\u0630\u0650\u064a\u0646\u064e \u0647\u064e\u0627\u062f\u064f\u0648\u0627 \u0633\u064e\u0645\u064e\u0651\u0627\u0639\u064f\u0648\u0646\u064e \u0644\u0650\u0644\u0652\u0643\u064e\u0630\u0650\u0628\u0650 \u0633\u064e\u0645\u064e\u0651\u0627\u0639\u064f\u0648\u0646\u064e \u0644\u0650\u0642\u064e\u0648\u0652\u0645\u064d \u0622\u062e\u064e\u0631\u0650\u064a\u0646\u064e \u0644\u064e\u0645\u0652 \u064a\u064e\u0623\u0652\u062a\u064f\u0648\u0643\u064e \u064a\u064f\u062d\u064e\u0631\u0650\u0651\u0641\u064f\u0648\u0646\u064e \u0627\u0644\u0652\u0643\u064e\u0644\u0650\u0645\u064e \u0645\u0650\u0646 \u0628\u064e\u0639\u0652\u062f\u0650 \u0645\u064e\u0648\u064e\u0627\u0636\u0650\u0639\u0650\u0647\u0650 \u064a\u064e\u0642\u064f\u0648\u0644\u064f\u0648\u0646\u064e \u0625\u0650\u0646\u0652 \u0623\u064f\u0648\u062a\u0650\u064a\u062a\u064f\u0645\u0652 \u0647\u064e\u0630\u064e\u0627 \u0641\u064e\u062e\u064f\u0630\u064f\u0648\u0647\u064f \u0648\u064e\u0625\u0650\u0646 \u0644\u064e\u0651\u0645\u0652 \u062a\u064f\u0624\u0652\u062a\u064e\u0648\u0652\u0647\u064f \u0641\u064e\u0627\u062d\u0652\u0630\u064e\u0631\u064f\u0648\u0627 \u0648\u064e\u0645\u064e\u0646 \u064a\u064f\u0631\u0650\u062f\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u064f \u0641\u0650\u062a\u0652\u0646\u064e\u062a\u064e\u0647\u064f \u0641\u064e\u0644\u064e\u0646 \u062a\u064e\u0645\u0652\u0644\u0650\u0643\u064e \u0644\u064e\u0647\u064f \u0645\u0650\u0646\u064e \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0634\u064e\u064a\u0652\u0626\u064b\u0627 \u0623\u064f\u0648\u0644\u064e\u0626\u0650\u0643\u064e \u0627\u0644\u064e\u0651\u0630\u0650\u064a\u0646\u064e \u0644\u064e\u0645\u0652 \u064a\u064f\u0631\u0650\u062f\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u064f \u0623\u064e\u0646 \u064a\u064f\u0637\u064e\u0647\u0650\u0651\u0631\u064e \u0642\u064f\u0644\u064f\u0648\u0628\u064e\u0647\u064f\u0645\u0652 \u0644\u064e\u0647\u064f\u0645\u0652 \u0641\u0650\u064a \u0627\u0644\u062f\u064f\u0651\u0646\u0652\u064a\u064e\u0627 \u062e\u0650\u0632\u0652\u064a\u064c \u0648\u064e\u0644\u064e\u0647\u064f\u0645\u0652 \u0641\u0650\u064a \u0627\u0644\u0652\u0622\u062e\u0650\u0631\u064e\u0629\u0650 \u0639\u064e\u0630\u064e\u0627\u0628\u064c \u0639\u064e\u0638\u0650\u064a\u0645\u064c"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:'O Messenger! Do not grieve for those who race to disbelieve\u2014those who say, "We believe" with their tongues, but their hearts are in disbelief. Nor those among the Jews who eagerly listen to lies, attentive to those who are too arrogant to come to you. They distort the Scripture, taking rulings out of context, then say, "If this is the ruling you get \u02f9from Mu\u1e25ammad\u02fa, accept it. If not, beware!" Whoever Allah allows to be deluded, you can never be of any help to them against Allah. It is not Allah\'s Will to purify their hearts.\n(English translation: Dr. Mustafa Khattab)'}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"The following verses also belong to the theme of distortion:"}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.a,{href:"https://quran.com/2?startingVerse=79",children:"2:79"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0641\u064e\u0648\u064e\u064a\u0652\u0644\u064c \u0644\u0650\u0651\u0644\u064e\u0651\u0630\u0650\u064a\u0646\u064e \u064a\u064e\u0643\u0652\u062a\u064f\u0628\u064f\u0648\u0646\u064e \u0627\u0644\u0652\u0643\u0650\u062a\u064e\u0627\u0628\u064e \u0628\u0650\u0623\u064e\u064a\u0652\u062f\u0650\u064a\u0647\u0650\u0645\u0652 \u062b\u064f\u0645\u064e\u0651 \u064a\u064e\u0642\u064f\u0648\u0644\u064f\u0648\u0646\u064e \u0647\u064e\u0630\u064e\u0627 \u0645\u0650\u0646\u0652 \u0639\u0650\u0646\u062f\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0644\u0650\u064a\u064e\u0634\u0652\u062a\u064e\u0631\u064f\u0648\u0627 \u0628\u0650\u0647\u0650 \u062b\u064e\u0645\u064e\u0646\u064b\u0627 \u0642\u064e\u0644\u0650\u064a\u0644\u064b\u0627 \u0641\u064e\u0648\u064e\u064a\u0652\u0644\u064c \u0644\u064e\u0651\u0647\u064f\u0645 \u0645\u0650\u0651\u0645\u064e\u0651\u0627 \u0643\u064e\u062a\u064e\u0628\u064e\u062a\u0652 \u0623\u064e\u064a\u0652\u062f\u0650\u064a\u0647\u0650\u0645\u0652 \u0648\u064e\u0648\u064e\u064a\u0652\u0644\u064c \u0644\u064e\u0651\u0647\u064f\u0645 \u0645\u0650\u0651\u0645\u064e\u0651\u0627 \u064a\u064e\u0643\u0652\u0633\u0650\u0628\u064f\u0648\u0646\u064e"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:'So woe to those who distort the Scripture with their own hands then say, "This is from Allah"\u2014seeking a fleeting gain! So woe to them for what their hands have written and woe to them for what they have earned.\n(English translation: Dr. Mustafa Khattab)'}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.a,{href:"https://quran.com/3?startingVerse=78",children:"3:78"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0648\u064e\u0625\u0650\u0646\u064e\u0651 \u0645\u0650\u0646\u0652\u0647\u064f\u0645\u0652 \u0644\u064e\u0641\u064e\u0631\u0650\u064a\u0642\u064b\u0627 \u064a\u064e\u0644\u0652\u0648\u064f\u0648\u0646\u064e \u0623\u064e\u0644\u0652\u0633\u0650\u0646\u064e\u062a\u064e\u0647\u064f\u0645 \u0628\u0650\u0627\u0644\u0652\u0643\u0650\u062a\u064e\u0627\u0628\u0650 \u0644\u0650\u062a\u064e\u062d\u0652\u0633\u064e\u0628\u064f\u0648\u0647\u064f \u0645\u0650\u0646\u064e \u0627\u0644\u0652\u0643\u0650\u062a\u064e\u0627\u0628\u0650 \u0648\u064e\u0645\u064e\u0627 \u0647\u064f\u0648\u064e \u0645\u0650\u0646\u064e \u0627\u0644\u0652\u0643\u0650\u062a\u064e\u0627\u0628\u0650 \u0648\u064e\u064a\u064e\u0642\u064f\u0648\u0644\u064f\u0648\u0646\u064e \u0647\u064f\u0648\u064e \u0645\u0650\u0646\u0652 \u0639\u0650\u0646\u062f\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0648\u064e\u0645\u064e\u0627 \u0647\u064f\u0648\u064e \u0645\u0650\u0646\u0652 \u0639\u0650\u0646\u062f\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0648\u064e\u064a\u064e\u0642\u064f\u0648\u0644\u064f\u0648\u0646\u064e \u0639\u064e\u0644\u064e\u0649 \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0627\u0644\u0652\u0643\u064e\u0630\u0650\u0628\u064e \u0648\u064e\u0647\u064f\u0645\u0652 \u064a\u064e\u0639\u0652\u0644\u064e\u0645\u064f\u0648\u0646\u064e"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:'There are some among them who distort the Book with their tongues to make you think this \u02f9distortion\u02fa is from the Book\u2014but it is not what the Book says. They say, "It is from Allah"\u2014but it is not from Allah. And \u02f9so\u02fa they attribute lies to Allah knowingly.\n(English translation: Dr. Mustafa Khattab)'}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:'The concept of "tahrif" had two interpretations in the history of Islamic theology:'}),"\n",(0,a.jsx)(t.p,{children:"(1)\n(the original)"}),"\n",(0,a.jsxs)(t.p,{children:['Tahrif al-ma\u02bfna (\u062a\u064e\u062d\u0652\u0631\u0650\u064a\u0641 \u0627\u0644\u0652\u0645\u064e\u0639\u0652\u0646\u064e\u0649) \u2014 "distortion of meaning":\nthe text of the Torah and the Gospel is authentic, but Jews and Christians misunderstand or misinterpret it.\n',(0,a.jsx)(t.em,{children:"The text itself has not been changed."})]}),"\n",(0,a.jsx)(t.p,{children:'This version was accepted, in particular, by al-Bukhari (the transmitter of hadith) and al-Tabari (the classical mufassir). Many classical commentators on the Quran read these same verses (2:75, 4:46) in precisely this way \u2014 as an accusation of distorting the interpretation, not the text. The very phrase "they move the words from their places" (4:46) they understood metaphorically \u2014 "they wrench out of context," "they interpret perversely."'}),"\n",(0,a.jsx)(t.p,{children:"(2)\n(the later one)"}),"\n",(0,a.jsxs)(t.p,{children:['Tahrif al-lafz (\u062a\u064e\u062d\u0652\u0631\u0650\u064a\u0641 \u0627\u0644\u0644\u064e\u0651\u0641\u0652\u0638) \u2014 "distortion of the [actual] wording/text":\nthe very text of the Torah and the Gospel has been physically corrupted: fragments cut out, fragments added, words substituted.\n',(0,a.jsx)(t.em,{children:"The text in its present form is not authentic."})]}),"\n",(0,a.jsxs)(t.p,{children:["In support of this interpretation (in particular, in the article on ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Tahrif",children:"Tahrif"})," on Wikipedia) one sometimes cites hadith ",(0,a.jsx)(t.a,{href:"https://sunnah.com/bukhari:7363",children:"Sahih al-Bukhari 7363"}),", which transmits the words of ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Ibn_Abbas",children:"Ibn Abbas"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0623\u064e\u0646\u064e\u0651 \u0623\u064e\u0647\u0652\u0644\u064e \u0627\u0644\u0652\u0643\u0650\u062a\u064e\u0627\u0628\u0650 \u0628\u064e\u062f\u064e\u0651\u0644\u064f\u0648\u0627 \u0643\u0650\u062a\u064e\u0627\u0628\u064e \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0648\u064e\u063a\u064e\u064a\u064e\u0651\u0631\u064f\u0648\u0647\u064f \u0648\u064e\u0643\u064e\u062a\u064e\u0628\u064f\u0648\u0627 \u0628\u0650\u0623\u064e\u064a\u0652\u062f\u0650\u064a\u0647\u0650\u0645\u064f \u0627\u0644\u0652\u0643\u0650\u062a\u064e\u0627\u0628\u064e \u0648\u064e\u0642\u064e\u0627\u0644\u064f\u0648\u0627 \u0647\u064f\u0648\u064e \u0645\u0650\u0646\u0652 \u0639\u0650\u0646\u0652\u062f\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650\u200f"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"... people of the scripture (Jews and Christians) changed their scripture and distorted it, and wrote the scripture with their own hands and said, 'It is from Allah,'"}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:['But in the same "Sahih al-Bukhari," in the section "Kitab al-Tawhid" / \u0643\u062a\u0627\u0628 \u0627\u0644\u062a\u0648\u062d\u064a\u062f, al-Bukhari gives the same statement of Ibn Abbas as in hadith ',(0,a.jsx)(t.a,{href:"https://sunnah.com/bukhari:7363",children:"7363"}),", in a fuller formulation that includes an important clarification:"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u064a\u064f\u062d\u064e\u0631\u0650\u0651\u0641\u064f\u0648\u0646\u064e \u064a\u064f\u0632\u0650\u064a\u0644\u064f\u0648\u0646\u064e \u0648\u064e\u0644\u064e\u064a\u0652\u0633\u064e \u0623\u064e\u062d\u064e\u062f\u064c \u064a\u064f\u0632\u0650\u064a\u0644\u064f \u0644\u064e\u0641\u0652\u0638\u064e \u0643\u0650\u062a\u064e\u0627\u0628\u064d \u0645\u0650\u0646\u0652 \u0643\u064f\u062a\u064f\u0628\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0639\u064e\u0632\u064e\u0651 \u0648\u064e\u062c\u064e\u0644\u064e\u0651 \u0648\u064e\u0644\u064e\u0643\u0650\u0646\u064e\u0651\u0647\u064f\u0645\u0652 \u064a\u064f\u062d\u064e\u0631\u0650\u0651\u0641\u064f\u0648\u0646\u064e\u0647\u064f \u064a\u064e\u062a\u064e\u0623\u064e\u0648\u064e\u0651\u0644\u064f\u0648\u0646\u064e\u0647\u064f \u0639\u064e\u0644\u064e\u0649 \u063a\u064e\u064a\u0652\u0631\u0650 \u062a\u064e\u0623\u0652\u0648\u0650\u064a\u0644\u0650\u0647\u0650"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:'Here \u064a\u064f\u062d\u064e\u0631\u0650\u0651\u0641\u064f\u0648\u0646\u064e \u064a\u064f\u0632\u0650\u064a\u0644\u064f\u0648\u0646\u064e\nis a gloss, a lexical clarification: "[the word meaning] yu\u1e25arrif\u016bna \u2014 [means] yuz\u012bl\u016bna." That is, Ibn Abbas gives a lexical equivalent for the Quranic verb \u064a\u064f\u062d\u064e\u0631\u0650\u0651\u0641\u064f\u0648\u0646\u064e used in 4:46 and 5:13. This is a typical device of early Islamic tafsir \u2014 explaining a rare word through a clearer synonym. My translation, accordingly:'}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:["They displace [the words from their places] (\u064a\u064f\u062d\u064e\u0631\u0650\u0651\u0641\u064f\u0648\u0646\u064e), that is, they alter [them] (\u064a\u064f\u0632\u0650\u064a\u0644\u064f\u0648\u0646), but ",(0,a.jsx)(t.em,{children:"no one can alter the text (laf\u1e93 / \u0644\u064e\u0641\u0652\u0638) of any of Allah's books"}),"; rather they distort [it], interpreting it not in accordance with its [deeper] meaning."]}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:["Characteristically, this text is present on sunnah.com (see ",(0,a.jsx)(t.a,{href:"https://sunnah.com/bukhari/97",children:"Book 97"})," at the beginning of the (55) Chapter, before hadith 7553), but ",(0,a.jsx)(t.em,{children:"without an English translation"})," \u2014 only the Arabic original. See also in Arabic on ",(0,a.jsx)(t.a,{href:"https://www.islamweb.net/ar/library/content/0/7226/",children:"islamweb.net"}),"."]}),"\n",(0,a.jsx)(t.p,{children:"I emphasize: this is a statement of Ibn Abbas (a companion and cousin of the Prophet Muhammad) that al-Bukhari cites precisely as a clarification of the expression used in verses 4:46 and 5:13, which are the central ones in the concept of tahrif. That is, the Sahaba (the first companions of Muhammad) understood it in exactly this way."}),"\n",(0,a.jsxs)(t.p,{children:['The idea of "tahrif al-lafz" (corruption of the text itself) as a systematic doctrine was introduced and substantiated only later \u2014 by ',(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Ibn_Hazm",children:"Ibn Hazm"})," in the 11th century CE (see ",(0,a.jsx)(t.a,{href:"https://www.amazon.co.uk/Exegesis-Polemical-Discourse-Christian-Scriptures/dp/0788503960",children:"Theodore Pulcini. Exegesis as Polemical Discourse: Ibn Hazm on Jewish and Christian Scriptures (1998)"}),")."]}),"\n",(0,a.jsxs)(t.p,{children:["Ibn Hazm based himself on a study of the text of the Torah, which he found too divergent from his own conceptions of Islam. Ibn Hazm advanced the hypothesis that, after the destruction of Jerusalem by the Babylonians, the Torah was lost, and that the existing text of the Torah was composed by ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Uzair",children:"Uzayr"})," (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Ezra",children:"Ezra"}),") after the return from the Babylonian captivity."]}),"\n",(0,a.jsx)(t.p,{children:"The question arises: how did Ibn Hazm deal with the above position of al-Bukhari, which cites Ibn Abbas? The answer: in no way. As far as I know, in his works Ibn Hazm does not address this passage in al-Bukhari."}),"\n",(0,a.jsx)(t.p,{children:"But nowadays, among Muslims \u2014 especially in the popular consciousness \u2014 it is the interpretation of tahrif set out by Ibn Hazm, and not by al-Bukhari, that has taken root as self-evident."}),"\n",(0,a.jsxs)(t.p,{children:["See, for example, the assertion of ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Zakir_Naik",children:"Zakir Naik"}),", one of the most popular contemporary ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Da%27i",children:"da'is"})," (Islamic preachers):"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"All the scriptures besides the Holy Quran have been changed by human being, they have been corrupted"}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:["(",(0,a.jsx)(t.a,{href:"https://zakirnaik.com/QA-CGMR-lecture/",children:"Zakir Naik: Concept of God in Major Religions // Mumbai, India, 26th Oct. 1997"}),")"]}),"\n",(0,a.jsx)(t.p,{children:'From my experience of conversing with Muslims, one can see that for many their attitude toward Jews is based on the conviction that the malicious Jews, out of their malice, corrupted the texts of the sacred Scriptures. That is, in effect the concept of tahrif, in its modern understanding \u2014 i.e. as "a change of the text" \u2014 is one of the bases of Muslims\' hostility toward Jews, and it plays the role of an insurmountable barrier between Islam and Judaism.'}),"\n",(0,a.jsx)(t.h2,{id:"arguments-against-the-concept-of-corruption-of-the-torahs-text",children:"Arguments against the concept of corruption of the Torah's text"}),"\n",(0,a.jsx)(t.p,{children:'Of course, there is an enormous difference between "a distorted interpretation of the text" and "a deliberate corruption of the text itself."'}),"\n",(0,a.jsx)(t.p,{children:'The concept of "tahrif al-ma\u02bfnawi" (distortion of the meaning of the Scriptures) \u2014 that some Jews and some Christians distorted the meaning of the texts by their interpretations \u2014 cannot provoke objection even among Jews and Christians themselves. What exactly was misinterpreted is, of course, a separate and difficult question deserving separate treatment, and here disputes are indeed possible; but as to the general assertion that "there were incorrect interpretations," such disputes are hardly possible.'}),"\n",(0,a.jsxs)(t.p,{children:['In this text, however, I will examine the arguments in favor of the view that the concept of "tahrif al-lafzi" (a corrupted text) of the ',(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Torah_in_Islam",children:"Tawrat"}),' (the Torah) is mistaken, and that, consequently, the correct interpretation of "tahrif" is precisely the one that originally existed in Islam.']}),"\n",(0,a.jsx)(t.h3,{id:"the-principal-argument-isa-jesus",children:"The principal argument: Isa (Jesus)"}),"\n",(0,a.jsx)(t.h4,{id:"the-verses-about-isa",children:"The verses about Isa"}),"\n",(0,a.jsx)(t.p,{children:"The Quran has 3 key verses in which the verb \u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u0627 (mu\u1e63addiqan \u2014 confirming) is used directly when speaking of Isa's (Jesus') mission in relation to the Tawrat (the Torah)."}),"\n",(0,a.jsx)(t.p,{children:"(1)"}),"\n",(0,a.jsxs)(t.p,{children:["Sura 3: Al-Imran (The Family of Imran)\n",(0,a.jsx)(t.a,{href:"https://quran.com/3?startingVerse=50",children:"3:50"}),":"]}),"\n",(0,a.jsx)(t.p,{children:"In this verse Isa addresses the children of Israel, explaining that his mission is to confirm the truth of the Torah."}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"\u0648\u064e\u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u06ed\u0627"})," \u0644\u0650\u0651\u0645\u064e\u0627 \u0628\u064e\u064a\u0652\u0646\u064e \u064a\u064e\u062f\u064e\u0649\u064e\u0651 \u0645\u0650\u0646\u064e \u0671\u0644\u062a\u064e\u0651\u0648\u0652\u0631\u064e\u0649\u0670\u0629\u0650"]}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:["...and to ",(0,a.jsx)(t.em,{children:"confirm"})," the Torah revealed before me...\n(English translation: Dr. Mustafa Khattab)"]}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"(2)"}),"\n",(0,a.jsxs)(t.p,{children:["Sura 5: Al-Ma'ida (The Table)\n",(0,a.jsx)(t.a,{href:"https://quran.com/5?startingVerse=46",children:"5:46"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:["\u0648\u064e\u0642\u064e\u0641\u064e\u0651\u064a\u0652\u0646\u064e\u0627 \u0639\u064e\u0644\u064e\u0649 \u0622\u062b\u064e\u0627\u0631\u0650\u0647\u0650\u0645 \u0628\u0650\u0639\u0650\u064a\u0633\u064e\u0649 \u0627\u0628\u0652\u0646\u0650 \u0645\u064e\u0631\u0652\u064a\u064e\u0645\u064e ",(0,a.jsx)(t.strong,{children:"\u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u0627"})," \u0644\u0650\u0651\u0645\u064e\u0627 \u0628\u064e\u064a\u0652\u0646\u064e \u064a\u064e\u062f\u064e\u064a\u0652\u0647\u0650 \u0645\u0650\u0646\u064e \u0627\u0644\u062a\u064e\u0651\u0648\u0652\u0631\u064e\u0627\u0629\u0650 \u0648\u064e\u0622\u062a\u064e\u064a\u0652\u0646\u064e\u0627\u0647\u064f \u0627\u0644\u0652\u0625\u0650\u0646\u062c\u0650\u064a\u0644\u064e \u0641\u0650\u064a\u0647\u0650 \u0647\u064f\u062f\u064b\u0649 \u0648\u064e\u0646\u064f\u0648\u0631\u064c \u0648\u064e\u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u0627 \u0644\u0650\u0651\u0645\u064e\u0627 \u0628\u064e\u064a\u0652\u0646\u064e \u064a\u064e\u062f\u064e\u064a\u0652\u0647\u0650 \u0645\u0650\u0646\u064e \u0627\u0644\u062a\u064e\u0651\u0648\u0652\u0631\u064e\u0627\u0629\u0650 \u0648\u064e\u0647\u064f\u062f\u064b\u0649 \u0648\u064e\u0645\u064e\u0648\u0652\u0639\u0650\u0638\u064e\u0629\u064b \u0644\u0650\u0651\u0644\u0652\u0645\u064f\u062a\u064e\u0651\u0642\u0650\u064a\u0646\u064e"]}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:["Then in the footsteps of the prophets, We sent Jesus, son of Mary, ",(0,a.jsx)(t.em,{children:"confirming"})," the Torah revealed before him. And We gave him the Gospel containing guidance and light and confirming what was revealed in the Torah\u2014a guide and a lesson to the God-fearing.\n(English translation: Dr. Mustafa Khattab)"]}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"(3)"}),"\n",(0,a.jsxs)(t.p,{children:["Sura 61: As-Saff (The Ranks)\n",(0,a.jsx)(t.a,{href:"https://quran.com/61?startingVerse=6",children:"61:6"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:["\u0648\u064e\u0625\u0650\u0630\u0652 \u0642\u064e\u0627\u0644\u064e \u0639\u0650\u064a\u0633\u064e\u0649 \u0627\u0628\u0652\u0646\u064f \u0645\u064e\u0631\u0652\u064a\u064e\u0645\u064e \u064a\u064e\u0627 \u0628\u064e\u0646\u0650\u064a \u0625\u0650\u0633\u0652\u0631\u064e\u0627\u0626\u0650\u064a\u0644\u064e \u0625\u0650\u0646\u0650\u0651\u064a \u0631\u064e\u0633\u064f\u0648\u0644\u064f \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0625\u0650\u0644\u064e\u064a\u0652\u0643\u064f\u0645 ",(0,a.jsx)(t.strong,{children:"\u0645\u064f\u0651\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u0627"})," \u0644\u0650\u0651\u0645\u064e\u0627 \u0628\u064e\u064a\u0652\u0646\u064e \u064a\u064e\u062f\u064e\u064a\u064e\u0651 \u0645\u0650\u0646\u064e \u0627\u0644\u062a\u064e\u0651\u0648\u0652\u0631\u064e\u0627\u0629\u0650"]}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:["And \u02f9remember\u02fa when Jesus, son of Mary, said, \"O children of Israel! I am truly Allah's messenger to you, ",(0,a.jsx)(t.em,{children:"confirming"})," the Torah which came before me...\n(English translation: Dr. Mustafa Khattab)"]}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:["A more literal (my own) translation of verse ",(0,a.jsx)(t.a,{href:"https://quran.com/61?startingVerse=6",children:"61:6"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:["And Jesus, son of Mary, said: O children of Israel, I am the ",(0,a.jsx)(t.em,{children:"messenger of Allah"})," (ras\u016blu-ll\u0101hi / \u0631\u064e\u0633\u064f\u0648\u0644\u064f \u0671\u0644\u0644\u064e\u0651\u0647\u0650 \u2014 the same expression by which Muhammad is designated in the ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Shahada",children:"shahada"}),") to you, ",(0,a.jsx)(t.em,{children:"confirming"})," (mu\u1e63addiqan / \u0645\u064f\u0651\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u06ed\u0627) ",(0,a.jsx)(t.em,{children:"that Tawrat (Torah) which is in my hands"})," (li-m\u0101 bayna yadayya mina t-tawr\u0101ti / \u0644\u0650\u0651\u0645\u064e\u0627 \u0628\u064e\u064a\u0652\u0646\u064e \u064a\u064e\u062f\u064e\u0649\u064e\u0651 \u0645\u0650\u0646\u064e \u0671\u0644\u062a\u064e\u0651\u0648\u0652\u0631\u064e\u0649\u0670\u0629\u0650)."]}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:['The key here is the expression \u0645\u064f\u0651\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u0627 \u0644\u0650\u0651\u0645\u064e\u0627 \u0628\u064e\u064a\u0652\u0646\u064e \u064a\u064e\u062f\u064e\u064a\u064e\u0651 \u0645\u0650\u0646\u064e \u0627\u0644\u062a\u064e\u0651\u0648\u0652\u0631\u064e\u0627\u0629\u0650 \u2014 "confirming that Tawrat which is in my hands" (see the analysis of this phrase on the ',(0,a.jsx)(t.a,{href:"https://corpus.quran.com/treebank.jsp?chapter=61&token=15&verse=6",children:"Quranic Arabic Corpus"}),")."]}),"\n",(0,a.jsx)(t.p,{children:'"In my hands" (\u0628\u064e\u064a\u0652\u0646\u064e \u064a\u064e\u062f\u064e\u0649\u064e\u0651 bayna-yadayya, cf. Hebrew \u05d1\u05b0\u05bc\u05d9\u05b8\u05d3\u05b7\u05d9 b\u0259-y\u0101\u1e0fay) \u2014 in Arabic (as, similarly, in other languages, including Hebrew) this is an idiomatic expression; that is, it is not implied that he is literally holding a scroll in his hands while speaking these words. But the expression shows quite clearly (through the use of the intelligible image "in my hands") that what is meant is the content (the text) of the Tawrat (the Torah) that Isa (Jesus) himself was using at that time.'}),"\n",(0,a.jsx)(t.p,{children:'Neither in Arabic nor in any other language can the idiomatic expression "that which is in my hands" denote "that which has long been lost or gone."'}),"\n",(0,a.jsxs)(t.p,{children:["And if, in this verse, addressing the Jews, he speaks to them of the Torah without making any special reservations, then he plainly means what they understand by the Torah \u2014 not selected passages from it (it is precisely a selective approach to Scripture that the Quran criticizes, see ",(0,a.jsx)(t.a,{href:"https://quran.com/2?startingVerse=85",children:"2:85"}),"), nor its ancient lost prototype."]}),"\n",(0,a.jsx)(t.p,{children:'In ordinary language, "to confirm" does not mean "to pick out a few correct fragments and stay silent about the rest." If a witness in court says, "I confirm X\'s testimony," this is understood as confirmation of X\'s testimony as a whole, unless the witness himself makes the reservation, "I confirm it only in such-and-such part." In just the same way, the Quran\'s phrase that Isa came to confirm (\u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u0627) the Torah naturally means confirmation of the Torah on hand as a whole. The reading "he confirmed only some true core unknown to us" contradicts the normal, unperverted understanding of the words.'}),"\n",(0,a.jsx)(t.p,{children:'A necessary qualification here: in Islam, as with the Torah in Judaism, "Tawrat" may refer not to the physical scroll or the text itself but to the content of the teaching. In other words, not so much the set of letters as the teaching it conveys; nevertheless, the form of its existence is text \u2014 written or spoken.'}),"\n",(0,a.jsx)(t.p,{children:'That is, the generally accepted variant of translating this point (including in Dr. Khattab\'s translation), "before me," is inexact; more exact would be "with me" or "at present." But the reason for this inexactness of translation is clear \u2014 the translators adjust to Ibn Hazm\'s concept: in their conception Isa confirms the Tawrat that existed long ago, whereas in fact the plain text clearly says otherwise \u2014 Isa confirms the text of the Tawrat that is "in his hands" at the moment of confirmation.'}),"\n",(0,a.jsxs)(t.p,{children:["But the point here, of course, is not so much how it should be translated as how the original Arabic text should be ",(0,a.jsx)(t.em,{children:"understood"}),"."]}),"\n",(0,a.jsx)(t.h4,{id:"the-text-of-the-tawrat-that-isa-used",children:"The text of the Tawrat that Isa used"}),"\n",(0,a.jsx)(t.p,{children:'So, we have established that the verses of the Quran unequivocally state that Isa confirmed the Tawrat that "was in his hands."'}),"\n",(0,a.jsx)(t.p,{children:"But today we can assert, with a sufficient degree of confidence, that we know what the text of the Torah (Tawrat) was in the time of Isa (Jesus). We have several fairly independent traditions of textual transmission from which we can draw conclusions:"}),"\n",(0,a.jsxs)(t.p,{children:["(1) ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Dead_Sea_Scrolls",children:'The "Dead Sea Scrolls"'})]}),"\n",(0,a.jsx)(t.p,{children:"These are ancient manuscripts found in the vicinity of the Dead Sea: in the caves of Qumran, in the caves of Wadi Murabba'at, and in other caves in the Judean Desert, as well as at Masada."}),"\n",(0,a.jsx)(t.p,{children:"Radiocarbon analysis dates the main body of these manuscripts to the period from 250 BCE to 68 CE."}),"\n",(0,a.jsx)(t.p,{children:"When all the scrolls of the Judean Desert are summed up (Qumran + Masada + Murabba'at + Hever + Sdeir + Tse'elim + Ein Gedi) and all the overlaps among them are taken into account, a significant portion of the verses of the Chumash is attested at least once."}),"\n",(0,a.jsx)(t.p,{children:"Not only the Pentateuch but almost the entire Tanakh is confirmed by these manuscripts. Only the scroll of Esther (the Book of Esther) is missing from the finds. Although the finds contain different recensions of the same texts, the differences among them are not significant in a theological sense."}),"\n",(0,a.jsxs)(t.p,{children:["(2) ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Septuagint",children:"The Septuagint"}),' ("The Translation of the Seventy Interpreters," also designated "LXX"):']}),"\n",(0,a.jsxs)(t.p,{children:["a translation of the Tanakh into Greek, carried out in the 3rd\u20132nd centuries BCE, which subsequently became the basis of the Christian textual tradition. Several very early manuscripts of this translation on papyri are known. For example, the papyrus ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Papyrus_Fouad_266",children:"Fouad 266"})," (1st century BCE) contains texts of Genesis and Deuteronomy (in Greek)."]}),"\n",(0,a.jsx)(t.p,{children:"The Septuagint constitutes an independent witness to the text of the Tanakh and confirms the existence of the canon at least as of the time the translation was composed."}),"\n",(0,a.jsxs)(t.p,{children:["(3) ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Samaritan_Pentateuch",children:"The Samaritan Pentateuch"})]}),"\n",(0,a.jsx)(t.p,{children:"The Samaritan tradition had been in conflict with the main branch of Judaism \u2014 to which Isa (Jesus) also belonged \u2014 roughly since the time of the Jews' return from the Babylonian captivity and the beginning of the building of the Second Temple."}),"\n",(0,a.jsxs)(t.p,{children:["The Samaritan Pentateuch contains differences, but apart from the designation of the principal cultic site (for the Samaritans this is Mount Gerizim), the rest are differences that, although numerous, are minor and do not substantially affect the meaning of the text. That is, on the whole we have before us the same text as the ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Masoretic_Text",children:"Masoretic Text"})," and the ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Septuagint",children:"Septuagint"}),". Moreover, the Samaritan Pentateuch is written in the ancient Hebrew alphabet (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Paleo-Hebrew_alphabet",children:"paleo-Hebrew alphabet"}),"), which the Jews used even before the Babylonian captivity."]}),"\n",(0,a.jsxs)(t.p,{children:["(4) And, finally, the ",(0,a.jsx)(t.a,{href:"https://he.wikipedia.org/wiki/%D7%9E%D7%A1%D7%95%D7%A8%D7%94",children:"Masorah (\u05de\u05e1\u05d5\u05e8\u05d4)"})," itself \u2014 the tradition of preserving the ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Masoretic_Text",children:"text"})," of the Tanakh, including the Pentateuch, in Judaism. A tradition rich in written sources, which \u2014 contrary to the notions widespread among contemporary Muslims \u2014 testifies that the Jews treated the preservation of the Torah's text with the utmost scrupulousness."]}),"\n",(0,a.jsx)(t.p,{children:"We do not claim that, as many believe, the Masoretic Text was written letter-for-letter by the hand of Moshe. It may be that in some places the Septuagint is closer to the original variant, and in some even the Samaritan Pentateuch. But we have grounds to assert that the text of the Pentateuch that we possess is the result of a tradition that strove to preserve the Torah of Moshe."}),"\n",(0,a.jsx)(t.p,{children:"And, most importantly, we now have in our hands (\u0628\u064e\u064a\u0652\u0646\u064e \u064a\u064e\u062f\u064e\u0649\u064e\u0651 bayna-yadayya) that text of the Torah which, according to the Quran, Isa confirmed."}),"\n",(0,a.jsx)(t.p,{children:"And the people of Israel did not corrupt this text; on the contrary \u2014 it is thanks to the people of Israel that this text has been preserved."}),"\n",(0,a.jsx)(t.p,{children:"And this text, therefore, according to the Quran, is the authentic exposition of the Tawrat \u2014 the revelation/teaching received by Musa (Moshe/Moses)."}),"\n",(0,a.jsxs)(t.p,{children:["This is the part of Islam that was not yet accessible to the Arabs in the time of Muhammad (there were no authoritative translations or means of understanding the text), but it ",(0,a.jsx)(t.em,{children:"must now be incorporated into the corpus of the foundational texts of Islam alongside the Quran"}),"."]}),"\n",(0,a.jsx)(t.h3,{id:"additional-arguments",children:"Additional arguments"}),"\n",(0,a.jsx)(t.h4,{id:"verses-with-a-grammatically-built-in-presumption-that-the-authentic-tawrat-was-in-the-possession-of-contemporaries",children:"Verses with a grammatically built-in presumption that the authentic Tawrat was in the possession of contemporaries"}),"\n",(0,a.jsxs)(t.p,{children:['These are verses containing a direct assertion of the presence of the authentic Tawrat (the Torah) "with them" / "with you" in the present tense: the Quranic text grammatically (by means of the prepositions ',(0,a.jsx)(t.em,{children:"ma\u02bfa"}),", ",(0,a.jsx)(t.em,{children:"\u02bfinda"}),' ( \u0639\u0650\u0646\u0652\u062f\u064e ,\u0645\u064e\u0639\u064e ) + an attached pronoun) fixes the Torah as actually being in the possession of the People of the Book, and precisely as the bearer of "the law/judgment of Allah" (\u1e25ukmu All\u0101hi \u2014 \u062d\u064f\u0643\u0652\u0645\u064f \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u2014 cognate with the Hebrew khokhm\u0101 \u2014 \u05d7\u05b8\u05db\u05b0\u05de\u05b8\u05d4 \u2014 wisdom (Arabic \u062d\u0650\u0643\u0652\u0645\u064e\u0629 \u1e25ikma)).']}),"\n",(0,a.jsxs)(t.h5,{id:"543",children:[(0,a.jsx)(t.a,{href:"https://quran.com/5?startingVerse=43",children:"5:43"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0648\u064e\u0639\u0650\u0646\u062f\u064e\u0647\u064f\u0645\u064f \u0671\u0644\u062a\u064e\u0651\u0648\u0652\u0631\u064e\u0649\u0670\u0629\u064f \u0641\u0650\u064a\u0647\u064e\u0627 \u062d\u064f\u0643\u0652\u0645\u064f \u0671\u0644\u0644\u064e\u0651\u0647\u0650"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"...they \u02f9already\u02fa have the Torah containing Allah's judgment..."}),"\n",(0,a.jsx)(t.p,{children:"(English translation: Dr. Mustafa Khattab)"}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:['"With them" (\u0639\u0650\u0646\u062f\u064e\u0647\u064f\u0645\u064f \u2014 indahumu) here means "with the Jews"; see the preceding verse 5:41 \u2014 the reference is to h\u0101d\u016b \u2014 ',(0,a.jsx)(t.a,{href:"https://corpus.quran.com/qurandictionary.jsp?q=hwd#(5:41:19)",children:"\u0647\u064e\u0627\u062f\u064f\u0648\u0627\u06df"}),', literally "those who became/are Jews."']}),"\n",(0,a.jsxs)(t.p,{children:["It is interesting here that ",(0,a.jsx)(t.a,{href:"https://quran.com/5?startingVerse=43",children:"5:43"})," follows ",(0,a.jsx)(t.a,{href:"https://quran.com/5?startingVerse=41",children:"5:41"}),', in which it is said of the Jews (or part of them) that they "distort the meaning of the words, taking them out of context" (\u064a\u064f\u062d\u064e\u0631\u0650\u0651\u0641\u064f\u0648\u0646\u064e \u0627\u0644\u0652\u0643\u064e\u0644\u0650\u0645\u064e \u0645\u0650\u0646 \u0628\u064e\u0639\u0652\u062f\u0650 \u0645\u064e\u0648\u064e\u0627\u0636\u0650\u0639\u0650\u0647\u0650), which is precisely tahrif.']}),"\n",(0,a.jsxs)(t.p,{children:["But one should note that, at the same time, those Jews \u2014 as is stated in ",(0,a.jsx)(t.a,{href:"https://quran.com/5?startingVerse=43",children:"5:43"}),' \u2014 have "the Torah containing the judgment (the law) of Allah" (\u0671\u0644\u062a\u064e\u0651\u0648\u0652\u0631\u064e\u0649\u0670\u0629\u064f \u0641\u0650\u064a\u0647\u064e\u0627 \u062d\u064f\u0643\u0652\u0645\u064f \u0671\u0644\u0644\u064e\u0651\u0647\u0650). That is, here it is plainly evident that the very text on hand among them does indeed contain the judgment (the law) of Allah, even though they "distort the meaning of the words" \u2014 i.e. interpret it incorrectly.']}),"\n",(0,a.jsx)(t.p,{children:'The construction "they have the Torah, in it the law/judgment of Allah" leaves no gap whatsoever: at the moment these words are uttered, the Torah that is in the Jews\' possession contains the authentic divine law.'}),"\n",(0,a.jsx)(t.p,{children:'Had the verse meant "it once contained, but is now corrupted," this thought would have had to be expressed differently, lexically or grammatically. For it to read as past tense ("that which in the past was with them"), one would have to insert the absent verb \u0643\u064e\u0627\u0646\u064e (k\u0101na "was"), which is not in the text. The default of a verbless nominal sentence is present/actual; a marked past would require \u0643\u064e\u0627\u0646\u064e (k\u0101na "was").'}),"\n",(0,a.jsxs)(t.h5,{id:"291",children:[(0,a.jsx)(t.a,{href:"https://quran.com/2?startingVerse=91",children:"2:91"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0648\u064e\u0647\u064f\u0648\u064e \u0627\u0644\u0652\u062d\u064e\u0642\u064f\u0651 \u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u0627 \u0644\u0650\u0651\u0645\u064e\u0627 \u0645\u064e\u0639\u064e\u0647\u064f\u0645\u0652"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"and it (the Quran) is the truth, confirming what they (the children of Israel) have"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"In Dr. Mustafa Khattab's translation:"}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:["...it is the ",(0,a.jsx)(t.em,{children:"truth confirming their own Scriptures"})]}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:["Here the Quran itself defines its status as ",(0,a.jsx)(t.em,{children:"confirming"}),' (\u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u0627 \u2014 musaddiqan) what the children of Israel have now (\u0645\u064e\u0639\u064e\u0647\u064f\u0645\u0652 \u2014 maeahum \u2014 "with them," in the present).']}),"\n",(0,a.jsx)(t.p,{children:"It is impossible to simultaneously (a) confirm what they have, and (b) teach that what they have is spurious."}),"\n",(0,a.jsxs)(t.h5,{id:"2101",children:[(0,a.jsx)(t.a,{href:"https://quran.com/2?startingVerse=101",children:"2:101"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0631\u064e\u0633\u064f\u0648\u0644\u064c\u06ed \u0645\u0650\u0651\u0646\u0652 \u0639\u0650\u0646\u062f\u0650 \u0671\u0644\u0644\u064e\u0651\u0647\u0650 \u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064c\u06ed \u0644\u0650\u0651\u0645\u064e\u0627 \u0645\u064e\u0639\u064e\u0647\u064f\u0645\u0652"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"In Dr. Mustafa Khattab's translation:"}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:["a messenger from Allah\u2014",(0,a.jsx)(t.em,{children:"confirming their own Scriptures"})]}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:["This is a continuation of what was set out in the preceding verse ",(0,a.jsx)(t.a,{href:"https://quran.com/2?startingVerse=91",children:"2:91"}),", but here the one who is ",(0,a.jsx)(t.em,{children:"confirming"})," (\u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064c\u06ed \u2014 musaddiqun) what the children of Israel have is Muhammad himself."]}),"\n",(0,a.jsxs)(t.h5,{id:"447",children:[(0,a.jsx)(t.a,{href:"https://quran.com/4?startingVerse=47",children:"4:47"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u064a\u064e\u0640\u0670\u0653\u0623\u064e\u064a\u064f\u0651\u0647\u064e\u0627 \u0671\u0644\u064e\u0651\u0630\u0650\u064a\u0646\u064e \u0623\u064f\u0648\u062a\u064f\u0648\u0627\u06df \u0671\u0644\u0652\u0643\u0650\u062a\u064e\u0640\u0670\u0628\u064e \u0621\u064e\u0627\u0645\u0650\u0646\u064f\u0648\u0627\u06df \u0628\u0650\u0645\u064e\u0627 \u0646\u064e\u0632\u064e\u0651\u0644\u0652\u0646\u064e\u0627 \u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u06ed\u0627 \u0644\u0650\u0651\u0645\u064e\u0627 \u0645\u064e\u0639\u064e\u0643\u064f\u0645"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"In Dr. Mustafa Khattab's translation:"}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsxs)(t.p,{children:["O you who were given the Scripture! Believe in what We have revealed, confirming ",(0,a.jsx)(t.em,{children:"what you already have"})]}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"A direct address to the People of the Book of that time: what is confirmed is precisely what is in their possession in the present (\u0645\u064e\u0639\u064e\u0643\u064f\u0645\u0652). The very act of the appeal loses its meaning if their Scripture is a forgery."}),"\n",(0,a.jsx)(t.h4,{id:"verses-with-demands-that-the-jews-read-or-observe-the-tawrat",children:"Verses with demands that the Jews read or observe the Tawrat"}),"\n",(0,a.jsxs)(t.h5,{id:"393",children:[(0,a.jsx)(t.a,{href:"https://quran.com/3?startingVerse=93",children:"3:93"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0641\u064e\u0623\u0652\u062a\u064f\u0648\u0627\u06df \u0628\u0650\u0671\u0644\u062a\u064e\u0651\u0648\u0652\u0631\u064e\u0649\u0670\u0629\u0650 \u0641\u064e\u0671\u062a\u0652\u0644\u064f\u0648\u0647\u064e\u0622"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"In Dr. Mustafa Khattab's translation:"}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"...Bring the Torah and read it..."}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:'Here a dispute of Muhammad\'s with the Jews about ancient dietary prohibitions is set out. The Quran, in the name of Allah, proposes to settle the dispute by appeal to the Torah \u2014 the Torah that can be "brought and read," i.e. to the actually available text.'}),"\n",(0,a.jsx)(t.p,{children:"This is a direct procedural recognition of the text of the Torah on hand at the time of the dispute as the basis for resolving a disputed (essentially halakhic) question."}),"\n",(0,a.jsxs)(t.h5,{id:"568",children:[(0,a.jsx)(t.a,{href:"https://quran.com/5?startingVerse=68",children:"5:68"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0642\u064f\u0644\u0652 \u064a\u064e\u0627 \u0623\u064e\u0647\u0652\u0644\u064e \u0627\u0644\u0652\u0643\u0650\u062a\u064e\u0627\u0628\u0650 \u0644\u064e\u0633\u0652\u062a\u064f\u0645\u0652 \u0639\u064e\u0644\u064e\u0649\u0670 \u0634\u064e\u064a\u0652\u0621\u064d \u062d\u064e\u062a\u064e\u0651\u0649\u0670 \u062a\u064f\u0642\u0650\u064a\u0645\u064f\u0648\u0627 \u0627\u0644\u062a\u064e\u0651\u0648\u0652\u0631\u064e\u0627\u0629\u064e \u0648\u064e\u0627\u0644\u0652\u0625\u0650\u0646\u062c\u0650\u064a\u0644\u064e \u0648\u064e\u0645\u064e\u0627 \u0623\u064f\u0646\u0632\u0650\u0644\u064e \u0625\u0650\u0644\u064e\u064a\u0652\u0643\u064f\u0645 \u0645\u0650\u0651\u0646 \u0631\u064e\u0651\u0628\u0650\u0651\u0643\u064f\u0645\u0652"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:'In Dr. Mustafa Khattab\'s translation:\nSay, \u02f9O Prophet,\u02fa "O People of the Book! You have nothing to stand on unless you observe the Torah, the Gospel, and what has been revealed to you from your Lord."'}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:'Naturally, this call to be guided by the Torah and by "what has been revealed to you from your Lord" (the books of the Prophets are evidently meant) presupposes that the Jews possess, in authentic form, that by which the Quran calls them to be guided.'}),"\n",(0,a.jsx)(t.h4,{id:"the-hadith-on-stoning",children:"The Hadith on Stoning."}),"\n",(0,a.jsx)(t.p,{children:"I consider it best to conclude the exposition of the arguments with precisely this one.\nThis is the account of Muhammad's handing down a sentence of stoning for adultery upon a Jew on the basis of the text of a Torah scroll brought by the Jews."}),"\n",(0,a.jsxs)(t.p,{children:["In the hadith collection of Abu Dawud (Sunan Abu Dawud) \u2014 one of the six canonical Sunni hadith collections (Kutub al-Sitta), usually regarded as the third in authority (after Sahih al-Bukhari and Sahih Muslim) \u2014 there is hadith 4449 (",(0,a.jsx)(t.a,{href:"https://sunnah.com/abudawud:4449",children:"Sunan Abi Dawud 4449"}),")."]}),"\n",(0,a.jsxs)(t.p,{children:["The status of this hadith is hasan (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Hadith_terminology#%E1%B8%A4asan",children:"\u1e24asan"}),"), i.e. of an acceptable degree of authenticity, admissible as an argument in religious-legal reasoning."]}),"\n",(0,a.jsx)(t.p,{children:"This hadith relates how a community of Jews invited Muhammad (evidently already the ruler of Medina) to the beit midrash (\u0628\u064a\u062a \u0627\u0644\u0645\u062f\u0631\u0627\u0633 / bayt al-midr\u0101s), approaching him with the request to pass judgement on a man of their community who had committed adultery."}),"\n",(0,a.jsx)(t.p,{children:"Muhammad asks the Jews to bring the Torah. It is brought. Muhammad withdraws the cushion on which he had been sitting and places the Torah scroll upon it \u2014 a rather symbolic act on the part of a ruler, demonstrating a hierarchy of authority \u2014 saying:"}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0622\u0645\u064e\u0646\u0652\u062a\u064f \u0628\u0650\u0643\u0650 \u0648\u064e\u0628\u0650\u0645\u064e\u0646\u0652 \u0623\u064e\u0646\u0652\u0632\u064e\u0644\u064e\u0643\u0650"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"I believed in thee and in Him Who revealed thee."}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"What is at issue here is precisely a materially existing scroll \u2014 the one brought by the Jews and laid by Muhammad upon the cushion \u2014 the contents of which Muhammad uses to render the sentence."}),"\n",(0,a.jsxs)(t.p,{children:["And let us note the principal point: here Muhammad does exactly what the Quran enjoins in ",(0,a.jsx)(t.a,{href:"https://quran.com/3?startingVerse=93",children:"3:93"}),' ("Bring the Torah and read it") and ',(0,a.jsx)(t.a,{href:"https://quran.com/5?startingVerse=43",children:"5:43"}),' ("they \u02f9already\u02fa have the Torah containing Allah\u2019s judgment"): he demands the extant scroll of the Jews of his own time, sets it symbolically above himself as a token of veneration, and on its basis hands down a judicial decision \u2014 that is, he treats it as a corpus of divine law in force.']}),"\n",(0,a.jsx)(t.h2,{id:"on-the-text-of-the-quran-itself",children:"On the text of the Quran itself"}),"\n",(0,a.jsxs)(t.p,{children:["Under Abu Bakr (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Abu_Bakr",children:"Abu Bakr"}),") \u2014 the first caliph \u2014 Zayd ibn Thabit (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Zayd_ibn_Thabit",children:"Zayd ibn Thabit"}),"), at the initiative of Umar (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Umar",children:"Umar"}),'), gathered the fragments of the Quran from "flat stones, palm leaves, the shoulder-blades of animals, and the memory of people." This compilation was kept by Abu Bakr, then by Umar, then by his daughter Hafsa (',(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Hafsa_bint_Umar",children:"Hafsa bint Umar"}),") \u2014 one of Muhammad's wives."]}),"\n",(0,a.jsxs)(t.p,{children:["Under Uthman (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Uthman",children:"Uthman"}),") \u2014 the third caliph \u2014 a new standardized version was created on the basis of Zayd's compilation. After this, Uthman sent out copies to the provinces and ordered all the other versions to be burned \u2014 including the versions belonging to the companions."]}),"\n",(0,a.jsxs)(t.p,{children:['This is a documented historical fact that the Islamic tradition itself does not deny. The burning of the alternative versions is confirmed in the most authoritative Sunni sources \u2014 in "Sahih al-Bukhari" (hadith ',(0,a.jsx)(t.a,{href:"https://sunnah.com/bukhari:4987",children:"4987"}),") it is directly described how Uthman ordered all the copies to be burned except the Uthmanic recension."]}),"\n",(0,a.jsx)(t.p,{children:'These "shoulder-blades, palm leaves, and flat stones," and the early manuscripts with the text of the Quran, ought to have been kept as sacred relics. But they were destroyed.'}),"\n",(0,a.jsx)(t.p,{children:"The destruction of the primary sources looks like a natural action for those who wish to exclude the possibility of verification."}),"\n",(0,a.jsx)(t.p,{children:"Can you imagine archaeologists finding an ancient parchment, copying out its text, and then burning the parchment itself \u2014 so that there would be no doubt as to the accuracy of the transmission of its text?"}),"\n",(0,a.jsx)(t.p,{children:"Or another example: witnesses gave testimony recorded in protocols; then this testimony was gathered and quoted in a court's decision, and the court ordered the original protocols of the testimony to be burned \u2014 so that there would be no doubt about what is written in the court's decision. Convincing?"}),"\n",(0,a.jsxs)(t.p,{children:["The preservation of the primary sources \u2014 the shoulder-blades, leaves, stones, and early manuscripts \u2014 would have been a natural action for those confident in the accuracy of the compilation. They would have served as proof of authenticity \u2014 this is exactly how the Jews kept the scrolls of the Torah until they wore out, and then ritually interred them in a genizah (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Genizah",children:"genizah"}),"), but did not destroy them."]}),"\n",(0,a.jsxs)(t.p,{children:["Moreover, Uthman ordered the burning of the Quranic copies (mushafs) of Ubayy ibn Ka'b (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Ubayy_ibn_Ka%27b",children:"Ubayy ibn Ka'b"}),") \u2014 Muhammad's secretary \u2014 and of Abdullah ibn Mas'ud (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Abd_Allah_ibn_Mas'ud",children:"Abd Allah ibn Mas'ud"}),'). And this despite the fact that, according to the collection "Sahih al-Bukhari" (hadiths ',(0,a.jsx)(t.a,{href:"https://sunnah.com/bukhari:3758",children:"3758"}),", ",(0,a.jsx)(t.a,{href:"https://sunnah.com/bukhari:3760",children:"3760"}),", ",(0,a.jsx)(t.a,{href:"https://sunnah.com/bukhari:4999",children:"4999"}),"), the Prophet Muhammad himself ordered the Muslims to learn the Quran ",(0,a.jsx)(t.em,{children:"precisely from Ibn Mas'ud and from Ubayy"}),". Early Muslim historians (Muhammad ibn Sa'd (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Ibn_Sa%27d",children:"Ibn Sa'd"}),")) related that Ibn Mas'ud did not recognize Zayd \u2014 who, unlike Ibn Mas'ud himself, had not been approved by Muhammad as an authority on questions of the Quran's text \u2014 and called on the Muslims to hide their mushafs."]}),"\n",(0,a.jsxs)(t.p,{children:["There exist reliable hadiths \u2014 for example, from Aisha (",(0,a.jsx)(t.a,{href:"https://sunnah.com/muslim:1452a",children:"Sahih Muslim 1452 a"}),") or from Umar (",(0,a.jsx)(t.a,{href:"https://sunnah.com/bukhari:6830",children:"Sahih al-Bukhari 6830"}),") \u2014 that mention verses which were known to the companions but did not enter Uthman's mushaf: the verse about stoning or the verse about the breastfeeding of adults. In hadith ",(0,a.jsx)(t.a,{href:"https://sunnah.com/muslim:1050",children:"Sahih Muslim 1050"})," Abu Musa al-Ash'ari (a companion of Muhammad) speaks of two lost suras."]}),"\n",(0,a.jsx)(t.p,{children:"All this, as far as I know, is unknown to the majority of contemporary Muslims, and the overwhelming majority of them believe that the text of the Torah was deliberately corrupted by the Jews, whereas the text of the Quran is directly what was dictated by Muhammad himself, and not the result of the work of a board that destroyed the primary sources and the alternative versions."}),"\n",(0,a.jsxs)(t.p,{children:["Although some contemporary Islamic scholars do acknowledge that the Quran is not a text dictated word-for-word by Muhammad. See, for example, the ",(0,a.jsx)(t.a,{href:"https://www.youtube.com/watch?v=GxTpkV8SCQA&t=892s",children:"talk"})," of ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Shabir_Ally",children:"Shabir Ally"}),', president of the Islamic Information & Dawah Centre International in Toronto, in which he says that the Uthmanic version of the Quran was produced during the lifetime of the Prophet\'s companions as "their best representation of what they knew collectively as the companions of the prophet."']}),"\n",(0,a.jsx)(t.p,{children:"An interesting situation results."}),"\n",(0,a.jsx)(t.p,{children:"For the Torah we have:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsx)(t.li,{children:"The Masoretic tradition, with a system of counting letters and words developed precisely to detect copying errors"}),"\n",(0,a.jsx)(t.li,{children:"The Septuagint \u2014 a Greek translation of the 3rd century BCE"}),"\n",(0,a.jsx)(t.li,{children:"The Qumran / Dead Sea Scrolls, showing that the text has changed minimally since then"}),"\n",(0,a.jsx)(t.li,{children:"The Samaritan Pentateuch \u2014 an independent tradition with insignificant variations"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"All of this makes it possible to verify the text through independent sources."}),"\n",(0,a.jsx)(t.p,{children:"For the Quran:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsx)(t.li,{children:"All the alternative versions have been destroyed, even though their existence among Muhammad's closest companions is documented"}),"\n",(0,a.jsx)(t.li,{children:"The original fragments and records, which one would think ought to have been kept as sacred artifacts, have been destroyed"}),"\n",(0,a.jsx)(t.li,{children:"Some Shia authorities of the first centuries of Islam themselves asserted that the Uthmanic recension was falsified \u2014 that verses confirming the status of Ali were removed from it"}),"\n",(0,a.jsx)(t.li,{children:"Ultraviolet analysis of the Sana'a palimpsest in the 21st century physically proved the existence of other textual versions of the Quran prior to Uthman's reform"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:'The paradox consists in this: the Torah \u2014 which the contemporary Islamic mainstream declares "corrupted" \u2014 has a far better textual base for verification than the Quran.'}),"\n",(0,a.jsx)(t.p,{children:"The text of the Quran was finalized not by Muhammad himself, and not even by those whom Muhammad himself designated as authorized authorities in the transmission of the Quran, but by a board created by Uthman that destroyed all the sources and the alternative versions."}),"\n",(0,a.jsx)(t.p,{children:"I do not assert that the text of the Quran was deliberately corrupted by Caliph Uthman's commission, but I wish to show that the naive notion of the majority of contemporary Muslims \u2014 that the modern text of the Quran is, letter-for-letter, the text dictated by Muhammad himself \u2014 is too far from reality."}),"\n",(0,a.jsxs)(t.p,{children:['Yes, one may believe that the editorial commission that compiled the "Quran of Uthman" (',(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Uthmanic_codex",children:"Uthmanic codex"}),") strove to transmit the content of Muhammad's preaching in the best possible way."]}),"\n",(0,a.jsx)(t.p,{children:"But the notion that the text of the Quran is a monolithic, letter-for-letter text dictated by the Most High without the possibility of editorial errors is theologically doomed from the outset. For the presence of any inaccuracies whatsoever would, on that view, refute the entire message of Muhammad."}),"\n",(0,a.jsxs)(t.p,{children:["Let us give a simple example. Verse ",(0,a.jsx)(t.a,{href:"https://quran.com/9?startingVerse=30",children:"9:30"}),":"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"\u0648\u064e\u0642\u064e\u0627\u0644\u064e\u062a\u0650 \u0627\u0644\u0652\u064a\u064e\u0647\u064f\u0648\u062f\u064f \u0639\u064f\u0632\u064e\u064a\u0652\u0631\u064c \u0627\u0628\u0652\u0646\u064f \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0648\u064e\u0642\u064e\u0627\u0644\u064e\u062a\u0650 \u0627\u0644\u0646\u064e\u0651\u0635\u064e\u0627\u0631\u064e\u0649 \u0627\u0644\u0652\u0645\u064e\u0633\u0650\u064a\u062d\u064f \u0627\u0628\u0652\u0646\u064f \u0627\u0644\u0644\u064e\u0651\u0647\u0650"}),"\n"]}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:'The Jews say, "Ezra is the son of Allah," while the Christians say, "The Messiah is the son of Allah."\n(English translation: Dr. Mustafa Khattab)'}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:'This is an error. In Judaism \u2014 whose history and theology are well documented \u2014 there was never a concept that Ezra (or any other human being) is the "son of the Most High." This ascribes to the Jews an idea, by analogy with the Christians, that the Jews never had. This can be asserted with a high degree of confidence, since the Jewish theological tradition, with all its currents and disputes, is documented in detail in written sources, in particular in the Jerusalem and Babylonian Talmuds.'}),"\n",(0,a.jsxs)(t.p,{children:['If the Quran is, in the literal (not metaphorical) sense, an exact copy of a "preserved tablet" residing in the heavens, from which ',(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Jibril",children:"the archangel Jibril"})," took texts that were then recorded with exactitude in the earthly text of the Quran, then this single error about Ezra demolishes the entire construction."]}),"\n",(0,a.jsxs)(t.p,{children:["If, however, the Quran is the result of the work of Zayd's editorial board, which strove in the best possible way \u2014 albeit over the objections of other companions \u2014 to transmit Muhammad's preaching, then there is nothing terrible in this inaccuracy; it is simply a mistaken ascription to the Jews of an analogue of the Christian concept of the \"Son of God.\" For although we regard the text of the Quran as a source of divine revelation, we understand that its transmission by humans cannot be entirely free of inaccuracies. And this, in particular \u2014 this passage in the Quran shows \u2014 means that the criticism of the Jews set out in the Quran must therefore be treated critically and checked for correspondence with the facts. This does not mean that all of it is unjust; it means only that it must be re-verified, since we know that it ",(0,a.jsx)(t.em,{children:"may"})," contain errors."]}),"\n",(0,a.jsx)(t.p,{children:"Yes, such an approach to divine revelation is more complex, since it requires engaging human reason to understand the sacred texts. But one may suppose that this was precisely the design of the Most High, who gave man reason. Moreover, I would say that a person who is afraid to engage his reason in reading texts that transmit divine revelation (be it the Quran or the Torah) in fact does not believe in it."}),"\n",(0,a.jsx)(t.h2,{id:"on-using-the-torah-to-clarify-the-meanings-of-the-quran",children:"On using the Torah to clarify the meanings of the Quran"}),"\n",(0,a.jsx)(t.p,{children:"The Quranic text itself is constructed not as self-sufficient but precisely as a supplement to the text of the Tawrat; in many cases it refers to the narratives of the Torah (the Tawrat) and cannot be understood without a knowledge of them \u2014 which is itself proof that the Quran acknowledges the existence of a text containing the authentic Tawrat of Musa. It is constructed in such a way as to presuppose its existence."}),"\n",(0,a.jsxs)(t.p,{children:["The Quran itself architecturally presupposes that the preceding Scripture is a verifying layer (see verses ",(0,a.jsx)(t.a,{href:"https://quran.com/10?startingVerse=94",children:"10:94"}),", ",(0,a.jsx)(t.a,{href:"https://quran.com/21?startingVerse=7",children:"21:7"}),"); the use of the Tawrat as a hermeneutic key for Quranic obscurities is its own instruction."]}),"\n",(0,a.jsxs)(t.p,{children:["In particular, if one acknowledges that we have the authentic text of the Tawrat, this makes it possible to resolve unequivocally the dispute about which son is meant in verses ",(0,a.jsx)(t.a,{href:"https://quran.com/37?startingVerse=99",children:"37:99-113"}),". Standard classical Islamic exegesis of the early period identified the sacrificial son as ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Isaac_in_Islam",children:"Isaac"}),". Later commentators, by now striving to interpret it differently from the Jews, interpret it as ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Ishmael_in_Islam",children:"Ishmael"}),". But if one uses the Tawrat as the hermeneutic support (",(0,a.jsx)(t.a,{href:"https://mechon-mamre.org/p/pt/pt0122.htm",children:"Bereshit 22"}),"), the answer becomes unequivocal: the sacrificial son is Isaac."]}),"\n",(0,a.jsxs)(t.p,{children:["This move works not only for the ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Binding_of_Isaac",children:"Aqedah"}),". It works for dozens of Quranic passages about figures of the Tanakh, where the Quran briefly mentions what the Tawrat recounts at length. If the Tawrat is a verifying layer, then many obscure passages of the Quran become clear. Thus, a serious reading of the Quran requires turning to the text of the Tawrat wherever the Quran sets out briefly what the Tawrat sets out at length."]}),"\n",(0,a.jsxs)(t.p,{children:["And such an approach follows the early Islamic tradition. ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Isra%CA%BCiliyyat",children:"Isra'iliyyat"})," (\u0625\u0633\u0631\u0627\u0626\u06cc\u0644\u06cc\u0627\u062a \u2014 ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Isra%CA%BCiliyyat",children:"Isra\u02bciliyyat"}),") \u2014 an entire genre of early tafsir (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Tafsir",children:"tafs\u012br"}),"), the tradition of interpreting the Quran, in which the interpreters turned to Jewish sources for precisely this purpose. Subsequently, for political reasons, Islam moved away from this tradition, but as is evident from the results of our inquiry, there are grounds to return to it."]}),"\n",(0,a.jsx)(t.h2,{id:"conclusions",children:"Conclusions"}),"\n",(0,a.jsx)(t.p,{children:"(1) Proceeding from the text of the Quran itself, the Quran is confirming (\u0645\u064f\u0635\u064e\u062f\u0650\u0651\u0642\u064b\u0627 \u2014 musaddiqan) of the Tawrat that was in the possession of the people of Israel at the moment of the Quran's revelation."}),"\n",(0,a.jsx)(t.p,{children:"(2) The corruption of the Tawrat (the Torah) \u2014 the tahrif spoken of in the Quran \u2014 implies distorted interpretations, but not a corruption of the actual existing text of the Tawrat."}),"\n",(0,a.jsx)(t.p,{children:"(3) The notion now generally accepted among Muslims, and constituting one of the factors of the religious conflict \u2014 that the malicious Jews deliberately falsified the text of the Torah \u2014 contradicts the plain text of the Quran and the original Islamic tradition, and must be rejected by Islam."}),"\n",(0,a.jsxs)(t.p,{children:["(4) The Tawrat \u2014 i.e. the Torah/Pentateuch \u2014 must be recognized, alongside the Quran, as a foundational text of the Quranic tradition, and, in particular, as a basis for the interpretation (",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Tafsir",children:"tafsir"}),") of the Quran, for the resolution of questions concerning Jerusalem and the Holy Land, for the content of the Tanakhic (i.e. ancient-Islamic) prophecies, and for the relations between the Islamic ummah and the people of Israel."]}),"\n",(0,a.jsx)(t.p,{children:"(5) The position set out here must become central in the Israeli-Muslim dialogue and one of the elements of building peace in the Middle East \u2014 peace that is possible only as a consequence of resolving the problematic religious questions."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"references",children:"References"}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.a,{href:"https://international-law.info/theology/al-aqsa/",children:'Ageyev, Viktor. Al-Aqsa. What is the "Al-Aqsa Mosque" mentioned in the Quran?'})}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.a,{href:"https://pinchaspolonsky.org/evrei-i-islam/",children:"Efraim Kholmiansky, Meir Antopolsky, Pinchas Polonsky. Jews and Islam: A History of the Conflict and a Path to Dialogue. Jerusalem, Orot Yerushalayim, 2022"})}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.a,{href:"https://islamqa.info/en/answers/2001/have-the-torah-and-gospel-been-changed",children:"Islam Q&A: Have the Torah and Gospel Been Changed?"})}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Tahrif",children:"Wikipedia: Tahrif"})}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.a,{href:"https://open.uct.ac.za/server/api/core/bitstreams/0cd80963-75fe-4501-990d-c950928458f2/content",children:"Abdul Rashied Omar. Ibn Hazm on the Doctrine of Tahrif. MA dissertation, University of Cape Town, 1992"})}),"\n",(0,a.jsxs)(t.p,{children:["Joseph A Islam, ",(0,a.jsx)(t.a,{href:"https://www.quransmessage.com/articles/between%20hands%20or%20before%20it%20FM3.htm",children:"'Between His Hands' Or 'Before It' (ma bayna yadayhi)"})," // quransmessage.com"]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.a,{href:"https://primaquran.com/2025/08/27/between-the-hands-or-having-authority-over-ma-bayna-yadayhi/",children:"Between the Hands or Having Authority Over (ma bayna yadayhi)"})," // Prima Quran"]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.a,{href:"https://primaquran.com/2025/10/03/the-quran-charges-oral-corruption-of-the-previous-revelations/",children:"The Qur\u2019an charges oral corruption of the previous revelations"})," // Prima Quran"]}),"\n",(0,a.jsx)(t.p,{children:"Gordon Nickel, Narratives of Tampering: Highlighting the Boundaries of Falsification in Qur'anic Commentary (2009)"}),"\n",(0,a.jsx)(t.p,{children:"Camilla Adang, \u0432 Muslim Writers on Judaism and the Hebrew Bible (1996)"}),"\n",(0,a.jsx)(t.p,{children:"Sayyid Ahmad Khan, Mohomedan Commentary on the Bible (Tabyin-ul-Kalam) (between 1862 and 1865)"})]})}function c(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},6178:(e,t,i)=>{i.d(t,{A:()=>n});const n=i.p+"assets/files/operation_al-aqsa_flood_logo-307e693abe16c1e4d708b20c2359ecc9.jpg"},8453:(e,t,i)=>{i.d(t,{R:()=>r,x:()=>h});var n=i(6540);const a={},s=n.createContext(a);function r(e){const t=n.useContext(s);return n.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function h(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);